bool _isRedPixel(int red, int green, int blue) {
  return red > 220 && green < 40 && blue < 40;
}

bool _isRedTextPixel(int red, int green, int blue) {
  return red > 150 && red > green * 2 && red > blue * 2;
}

bool _isDarkTextPixel(int red, int green, int blue) {
  return red < 80 && green < 80 && blue < 80;
}

bool _isSelectionBluePixel(int red, int green, int blue) {
  return red < 40 && green > 110 && green < 170 && blue > 220;
}

bool _isScrollbarThumbPixel(int red, int green, int blue) {
  return (red - 0xb7).abs() <= 3 &&
      (green - 0xb7).abs() <= 3 &&
      (blue - 0xc0).abs() <= 3;
}

bool _isPrintAreaBoundaryPixel(int red, int green, int blue) {
  return red > 200 && green > 100 && green < 210 && blue < 110;
}

bool _isGridLinePixel(int red, int green, int blue) {
  return (red - 0xdf).abs() <= 3 &&
      (green - 0xdf).abs() <= 3 &&
      (blue - 0xdf).abs() <= 3;
}

bool _isNonWhiteUiPixel(int red, int green, int blue) {
  return red < 248 || green < 248 || blue < 248;
}

bool _isToolbarPopupScrollIndicatorPixel(int red, int green, int blue) {
  return (red - 0x5f).abs() <= 2 &&
      (green - 0x63).abs() <= 2 &&
      (blue - 0x68).abs() <= 2;
}

bool _isToolbarPopupTextPixel(int red, int green, int blue) {
  return red < 90 && green < 90 && blue < 90;
}

bool _isRulerTickPixel(int red, int green, int blue) {
  return red < 150 &&
      green < 155 &&
      blue < 165 &&
      (red - green).abs() <= 18 &&
      (green - blue).abs() <= 18;
}

bool _isToolbarPopupScrollButtonHoverPixel(int red, int green, int blue) {
  return red > 238 &&
      red < 255 &&
      green > 238 &&
      green < 255 &&
      blue > 238 &&
      blue < 255;
}

int _countPixels(
  ByteData bytes,
  int imageWidth,
  Rect rect,
  bool Function(int red, int green, int blue) test,
) {
  var pixels = 0;
  for (var y = rect.top.floor(); y < rect.bottom.ceil(); y += 1) {
    for (var x = rect.left.floor(); x < rect.right.ceil(); x += 1) {
      final offset = ((y * imageWidth) + x) * 4;
      final red = bytes.getUint8(offset);
      final green = bytes.getUint8(offset + 1);
      final blue = bytes.getUint8(offset + 2);
      if (test(red, green, blue)) {
        pixels += 1;
      }
    }
  }
  return pixels;
}

int _countChangedPixels(
  ByteData before,
  ByteData after,
  int imageWidth,
  Rect rect,
) {
  var pixels = 0;
  for (var y = rect.top.floor(); y < rect.bottom.ceil(); y += 1) {
    for (var x = rect.left.floor(); x < rect.right.ceil(); x += 1) {
      final offset = ((y * imageWidth) + x) * 4;
      if (before.getUint8(offset) != after.getUint8(offset) ||
          before.getUint8(offset + 1) != after.getUint8(offset + 1) ||
          before.getUint8(offset + 2) != after.getUint8(offset + 2) ||
          before.getUint8(offset + 3) != after.getUint8(offset + 3)) {
        pixels += 1;
      }
    }
  }
  return pixels;
}

Rect? _pixelBounds(
  ByteData bytes,
  int imageWidth,
  Rect rect,
  bool Function(int red, int green, int blue) test,
) {
  var left = rect.right.ceil();
  var top = rect.bottom.ceil();
  var right = rect.left.floor();
  var bottom = rect.top.floor();
  var found = false;
  for (var y = rect.top.floor(); y < rect.bottom.ceil(); y += 1) {
    for (var x = rect.left.floor(); x < rect.right.ceil(); x += 1) {
      final offset = ((y * imageWidth) + x) * 4;
      final red = bytes.getUint8(offset);
      final green = bytes.getUint8(offset + 1);
      final blue = bytes.getUint8(offset + 2);
      if (test(red, green, blue)) {
        found = true;
        left = math.min(left, x);
        top = math.min(top, y);
        right = math.max(right, x + 1);
        bottom = math.max(bottom, y + 1);
      }
    }
  }
  return found
      ? Rect.fromLTRB(
          left.toDouble(),
          top.toDouble(),
          right.toDouble(),
          bottom.toDouble(),
        )
      : null;
}

void main() {
  test('formula search parameter public helper exposes display labels', () {
    const requiredParameter = FortuneFormulaSearchParameter(
      name: 'value',
      detail: 'value to add',
      example: '1',
    );
    const optionalParameter = FortuneFormulaSearchParameter(
      name: 'criteria',
      optional: true,
    );
    const repeatedParameter = FortuneFormulaSearchParameter(
      name: 'value',
      repeat: true,
    );
    const optionalRepeatedParameter = FortuneFormulaSearchParameter(
      name: 'value',
      optional: true,
      repeat: true,
    );
    const entry = FortuneFormulaSearchFunction(
      name: 'SUM',
      categoryType: 0,
      description: 'Adds values.',
      parameterHint: 'value1, value2',
      detail: '',
      parameters: [requiredParameter],
    );

    expect(requiredParameter.displayName, 'value');
    expect(optionalParameter.displayName, '[criteria]');
    expect(repeatedParameter.displayName, 'value, ...');
    expect(optionalRepeatedParameter.displayName, '[value, ...]');
    expect(entry.parameters.single, isA<FortuneFormulaSearchParameter>());
    expect(entry.hasDetailedHelp, isTrue);
    expect(entry.exampleSignature, 'SUM(1)');
  });

  test('formula search category menu labels keep descenders visible', () async {
    const size = Size(640, 420);
    final painter = FortuneSheetPainter(
      workbook: FortuneWorkbook(
        sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
      ),
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
      formulaSearchDialogOpen: true,
      formulaSearchCategoryType: 9,
      formulaSearchCategoryMenuOpen: true,
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    painter.paint(canvas, size);
    final image = await recorder.endRecording().toImage(
      size.width.toInt(),
      size.height.toInt(),
    );
    final bytes = (await image.toByteData(format: ui.ImageByteFormat.rawRgba))!;

    final dialogRect = fortuneFormulaSearchDialogRect(size);
    final menuRect = fortuneFormulaSearchCategoryMenuRect(dialogRect);
    final engineeringIndex = fortuneFormulaSearchCategories.indexWhere(
      (category) => category.label == 'Engineering',
    );
    final row = Rect.fromLTWH(
      menuRect.left,
      menuRect.top +
          engineeringIndex * fortuneFormulaSearchCategoryOptionHeight,
      menuRect.width,
      fortuneFormulaSearchCategoryOptionHeight,
    );
    final descenderBand = Rect.fromLTRB(
      row.left + 8,
      row.top + 16,
      row.right - 8,
      row.top + 22,
    );

    expect(
      _countPixels(
        bytes,
        size.width.toInt(),
        descenderBand,
        _isToolbarPopupTextPixel,
      ),
      greaterThan(0),
    );
  });

  test(
    'adjusted sheet paints print area boundary without clipping grid',
    () async {
      const size = Size(420, 320);
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            rowCount: 30,
            columnCount: 20,
            extraFields: const {
              fortuneSheetGridClientWidthMmKey: 40,
              fortuneSheetGridClientHeightMmKey: 30,
            },
          ),
        ],
      );
      final painter = FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        sheetRulerVisible: true,
      );

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      painter.paint(canvas, size);
      final image = await recorder.endRecording().toImage(
        size.width.toInt(),
        size.height.toInt(),
      );
      final bytes = (await image.toByteData(
        format: ui.ImageByteFormat.rawRgba,
      ))!;
      final settings = workbook.settings;
      final sheetTop =
          settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
      final dataLeft = settings.rowHeaderWidth * 2;
      final dataTop = sheetTop + settings.columnHeaderHeight * 2;
      final boundaryX =
          settings.rowHeaderWidth * 2 + fortuneMillimetersToLogicalPixels(40);
      final boundaryY = dataTop + fortuneMillimetersToLogicalPixels(30);
      final metrics = workbook.activeSheet.metrics(settings);

      expect(
        _countPixels(
          bytes,
          size.width.toInt(),
          Rect.fromLTWH(boundaryX - 2, dataTop, 4, boundaryY - dataTop),
          _isPrintAreaBoundaryPixel,
        ),
        greaterThan(90),
      );
      expect(
        _countPixels(
          bytes,
          size.width.toInt(),
          Rect.fromLTWH(dataLeft, boundaryY - 2, boundaryX - dataLeft, 4),
          _isPrintAreaBoundaryPixel,
        ),
        greaterThan(90),
      );
      expect(
        _countPixels(
          bytes,
          size.width.toInt(),
          Rect.fromLTWH(boundaryX - 2, boundaryY + 8, 4, 42),
          _isPrintAreaBoundaryPixel,
        ),
        0,
      );
      expect(
        _countPixels(
          bytes,
          size.width.toInt(),
          Rect.fromLTWH(boundaryX + 8, boundaryY - 2, 42, 4),
          _isPrintAreaBoundaryPixel,
        ),
        0,
      );
      expect(
        _countPixels(
          bytes,
          size.width.toInt(),
          Rect.fromLTWH(
            size.width - 54,
            sheetTop + settings.columnHeaderHeight - 2,
            44,
            4,
          ),
          _isNonWhiteUiPixel,
        ),
        greaterThan(5),
      );
      expect(
        _countPixels(
          bytes,
          size.width.toInt(),
          Rect.fromLTWH(
            size.width - 54,
            dataTop + metrics.rowEnd(0) - 2,
            44,
            4,
          ),
          _isGridLinePixel,
        ),
        greaterThan(20),
      );
    },
  );

