            rowCount: 8,
            columnCount: 8,
            showGridLines: false,
            extraFields: const {
              fortuneSheetGridClientWidthMmKey: 40,
              fortuneSheetGridClientHeightMmKey: 30,
            },
            borderInfo: const [
              FortuneBorderInfo(
                rangeType: 'range',
                borderType: 'border-right',
                color: Color(0xff000000),
                style: 13,
                ranges: [
                  FortuneRange(
                    rowStart: 0,
                    rowEnd: 0,
                    columnStart: 0,
                    columnEnd: 0,
                  ),
                ],
              ),
            ],
          ),
        ],
      );
      const size = Size(420, 260);
      final painter = FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 5, column: 5),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        sheetRulerVisible: true,
      );

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      painter.paint(canvas, size);
      final image = await recorder.endRecording().toImage(
        size.width.toInt(),
        size.height.toInt(),
      );
      final bytes = (await image.toByteData(
        format: ui.ImageByteFormat.rawRgba,
      ))!;
      final settings = workbook.settings;
      final sheetTop =
          settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
      final dataTop = sheetTop + settings.columnHeaderHeight * 2;
      final boundaryX = settings.rowHeaderWidth * 2 + boundaryWidth;
      final overlapRect = Rect.fromLTWH(boundaryX - 2, dataTop, 4, 60);

      expect(
        _countPixels(bytes, image.width, overlapRect, _isDarkTextPixel),
        greaterThan(35),
      );
      expect(
        _countPixels(
          bytes,
          image.width,
          overlapRect,
          _isPrintAreaBoundaryPixel,
        ),
        0,
      );
    },
  );

  test('adjusted sheet ruler ticks follow sheet zoom', () async {
    const size = Size(420, 320);
    const zoomRatio = 2.0;
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 30,
          columnCount: 20,
          zoomRatio: zoomRatio,
          extraFields: const {
            fortuneSheetGridClientWidthMmKey: 40,
            fortuneSheetGridClientHeightMmKey: 30,
          },
        ),
      ],
    );
    final painter = FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
      sheetRulerVisible: true,
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    painter.paint(canvas, size);
    final image = await recorder.endRecording().toImage(
      size.width.toInt(),
      size.height.toInt(),
    );
    final bytes = (await image.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    ))!;
    final settings = workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final rulerTop = sheetTop;
    final rulerBottom = sheetTop + settings.columnHeaderHeight;
    final dataLeft = settings.rowHeaderWidth * 2;
    final unzoomedTenMmX = dataLeft + fortuneMillimetersToLogicalPixels(10);
    final zoomedTenMmX =
        dataLeft + fortuneMillimetersToLogicalPixels(10) * zoomRatio;

    expect(
      _countPixels(
        bytes,
        size.width.toInt(),
        Rect.fromLTWH(zoomedTenMmX - 2, rulerBottom - 15, 5, 7),
        _isRulerTickPixel,
      ),
      greaterThan(0),
    );
    expect(
      _countPixels(
        bytes,
        size.width.toInt(),
        Rect.fromLTWH(unzoomedTenMmX - 2, rulerTop + 1, 5, 7),
        _isRulerTickPixel,
      ),
      0,
    );
  });

