  test('inline typography extras affect completed cell painting', () async {
    const fontSize = 28.0;
    const rowHeight = 96.0;
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          showGridLines: false,
          defaultRowHeight: rowHeight,
          defaultColWidth: 320,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'WWWW',
              fontSize: fontSize,
              inlineRuns: [
                FortuneInlineTextRun(
                  text: 'WWWW',
                  foreground: Color(0xffff0000),
                  fontSize: fontSize,
                ),
              ],
            ),
            const FortuneCellCoord(1, 0): const FortuneCell(
              value: 'WWWW',
              fontSize: fontSize,
              inlineRuns: [
                FortuneInlineTextRun(
                  text: 'WWWW',
                  foreground: Color(0xffff0000),
                  fontSize: fontSize,
                  extraFields: {'letterSpacing': 2.0, 'fontScale': 150.0},
                ),
              ],
            ),
            const FortuneCellCoord(2, 0): const FortuneCell(
              value: 'A\nA',
              fontSize: fontSize,
              textWrap: '2',
              inlineRuns: [
                FortuneInlineTextRun(
                  text: 'A\nA',
                  foreground: Color(0xffff0000),
                  fontSize: fontSize,
                ),
              ],
            ),
            const FortuneCellCoord(3, 0): const FortuneCell(
              value: 'A\nA',
              fontSize: fontSize,
              textWrap: '2',
              inlineRuns: [
                FortuneInlineTextRun(
                  text: 'A\nA',
                  foreground: Color(0xffff0000),
                  fontSize: fontSize,
                  extraFields: {'lineHeight': 2.0},
                ),
              ],
            ),
          },
        ),
      ],
    );

    const size = Size(420, 560);
    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, size);
    final image = await recorder.endRecording().toImage(
      size.width.toInt(),
      size.height.toInt(),
    );
    final bytes = (await image.toByteData(format: ui.ImageByteFormat.rawRgba))!;
    final sheetTop =
        workbook.settings.effectiveToolbarHeight +
        workbook.settings.effectiveFormulaBarHeight;
    final bodyTop = sheetTop + workbook.settings.columnHeaderHeight;
    final rowLeft = workbook.settings.rowHeaderWidth;
    Rect rowRect(int row) => Rect.fromLTWH(
      rowLeft,
      bodyTop + rowHeight * row,
      workbook.activeSheet.defaultColWidth!,
      rowHeight,
    );

    final normalWidthBounds = _pixelBounds(
      bytes,
      image.width,
      rowRect(0),
      _isRedTextPixel,
    );
    final scaledWidthBounds = _pixelBounds(
      bytes,
      image.width,
      rowRect(1),
      _isRedTextPixel,
    );
    final normalLineBounds = _pixelBounds(
      bytes,
      image.width,
      rowRect(2),
      _isRedTextPixel,
    );
    final tallerLineBounds = _pixelBounds(
      bytes,
      image.width,
      rowRect(3),
      _isRedTextPixel,
    );

    expect(normalWidthBounds, isNotNull);
    expect(scaledWidthBounds, isNotNull);
    expect(normalLineBounds, isNotNull);
    expect(tallerLineBounds, isNotNull);
    expect(
      scaledWidthBounds!.width,
      greaterThan(normalWidthBounds!.width * 1.3),
    );
    expect(tallerLineBounds!.height, greaterThan(normalLineBounds!.height + 8));
  });

  test('zoom scales inline typography extras in completed cell painting', () async {
    const fontSize = 28.0;
    const rowHeight = 120.0;

    Future<({Rect widthBounds, Rect lineBounds})> paintAtZoom(
      double zoomRatio,
    ) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            showGridLines: false,
            zoomRatio: zoomRatio,
            defaultRowHeight: rowHeight,
            defaultColWidth: 420,
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(
                value: 'WIDE2',
                fontSize: fontSize,
                inlineRuns: [
                  FortuneInlineTextRun(
                    text: 'WIDE',
                    foreground: Color(0xffff0000),
                    fontSize: fontSize,
                    extraFields: {'letterSpacing': 2.0, 'fontScale': 150.0},
                  ),
                  FortuneInlineTextRun(
                    text: '2',
                    foreground: Color(0xffff0000),
                    fontSize: fontSize * fortuneInlineScriptFontSizeScale,
                    extraFields: {'script': 'superscript'},
                  ),
                ],
              ),
              const FortuneCellCoord(1, 0): const FortuneCell(
                value: 'A\nA',
                fontSize: fontSize,
                textWrap: '2',
                inlineRuns: [
                  FortuneInlineTextRun(
                    text: 'A\nA',
                    foreground: Color(0xffff0000),
                    fontSize: fontSize,
                    extraFields: {'lineHeight': 2.0},
                  ),
                ],
              ),
            },
          ),
        ],
      );

      const size = Size(760, 520);
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, size);
      final image = await recorder.endRecording().toImage(
        size.width.toInt(),
        size.height.toInt(),
      );
      final bytes = (await image.toByteData(format: ui.ImageByteFormat.rawRgba))!;
      final settings = workbook.settings;
      final metrics = workbook.activeSheet.metrics(settings);
      final sheetTop =
          settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
      final bodyTop = sheetTop + settings.columnHeaderHeight;
      final rowLeft = settings.rowHeaderWidth;

      Rect rowRect(int row) => Rect.fromLTWH(
        rowLeft,
        bodyTop + metrics.rowStart(row),
        metrics.columnEnd(0) - metrics.columnStart(0),
        metrics.rowEnd(row) - metrics.rowStart(row),
      );

      final widthBounds = _pixelBounds(
        bytes,
        image.width,
        rowRect(0),
        _isRedTextPixel,
      );
      final lineBounds = _pixelBounds(
        bytes,
        image.width,
        rowRect(1),
        _isRedTextPixel,
      );
      image.dispose();

      expect(widthBounds, isNotNull);
      expect(lineBounds, isNotNull);
      return (widthBounds: widthBounds!, lineBounds: lineBounds!);
    }

    final normal = await paintAtZoom(1);
    final zoomed = await paintAtZoom(1.5);

    expect(zoomed.widthBounds.width, greaterThan(normal.widthBounds.width * 1.3));
    expect(zoomed.widthBounds.height, greaterThan(normal.widthBounds.height * 1.3));
    expect(zoomed.lineBounds.height, greaterThan(normal.lineBounds.height * 1.3));
  });

  test('cell render hooks receive cell and bounds', () {
    final beforeCalls = <Map<String, Object?>>[];
    final afterCalls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      settings: FortuneSettings(
        beforeRenderCell: (cell, info, canvas) {
          if (cell?.value == '30') {
            beforeCalls.add({
              'value': cell?.value,
              'type': cell?.cellType?.type,
              'info': Map<String, num>.from(info),
            });
          }
          return true;
        },
        afterRenderCell: (cell, info, canvas) {
          if (cell?.value == '30') {
            afterCalls.add({
              'value': cell?.value,
              'type': cell?.cellType?.type,
              'info': Map<String, num>.from(info),
            });
          }
        },
      ),
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: '30',
              cellType: FortuneCellType(type: 'n'),
            ),
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(220, 160));
    recorder.endRecording();

    expect(beforeCalls, [
      {
        'value': '30',
        'type': 'n',
        'info': {
          'row': 0,
          'column': 0,
          'startX': 46.0,
          'startY': 20.0,
          'endX': 120.0,
          'endY': 40.0,
        },
      },
    ]);
    expect(afterCalls, beforeCalls);
  });

  test('dynamic array compute values render over empty styled cells', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          showGridLines: false,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              foreground: Color(0xffff0000),
            ),
          },
          dynamicArrayCompute: const {
            '0_0': {'v': 'SPILL'},
          },
          hasRawDynamicArrayCompute: true,
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(220, 160));
    final image = await recorder.endRecording().toImage(220, 160);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var redPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && green < 80 && blue < 80) {
          redPixels += 1;
        }
      }
    }

    expect(redPixels, greaterThan(8));
  });

