                    extraFields: {'lineHeight': lineHeight},
                  ),
                  FortuneInlineTextRun(
                    text: 'DEF',
                    foreground: Color(0xffff0000),
                    fontSize: scriptFontSize,
                    extraFields: {
                      'lineHeight': lineHeight,
                      'script': 'superscript',
                    },
                  ),
                  FortuneInlineTextRun(
                    text: 'GHIJKLMN\nABCDEFGHIJKLMN',
                    fontSize: baseFontSize,
                    extraFields: {'lineHeight': lineHeight},
                  ),
                ],
              ),
