        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(440, 300));
      final image = await recorder.endRecording().toImage(440, 300);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      final sheetTop =
          workbook.settings.effectiveToolbarHeight +
          workbook.settings.effectiveFormulaBarHeight;
      final bodyTop = sheetTop + workbook.settings.columnHeaderHeight;
      final rowLeft = workbook.settings.rowHeaderWidth;
      final cellRect = Rect.fromLTWH(rowLeft, bodyTop, 360, rowHeight);
      final redBounds = _pixelBounds(
        bytes!,
        image.width,
        cellRect,
        _isRedTextPixel,
      );
      final blackBounds = _pixelBounds(
        bytes,
        image.width,
        Rect.fromLTWH(rowLeft, redBounds?.top ?? bodyTop, 360, 34),
        _isDarkTextPixel,
      );
      final allTextBounds = _pixelBounds(
        bytes,
        image.width,
        cellRect,
        (red, green, blue) =>
