      expect(blackBounds, isNotNull);
      expect(allTextBounds, isNotNull);
      expect(redBounds!.top, lessThan(blackBounds!.top));
      expect(allTextBounds!.height, greaterThan(baseFontSize * lineHeight * 2));
    },
  );

