              merge: FortuneCellMerge(row: 0, column: 0),
            ),
          },
          borderInfo: const [
            FortuneBorderInfo(
              rangeType: 'range',
              borderType: 'border-all',
              color: Color(0xffff0000),
              style: 13,
              ranges: [
                FortuneRange(
                  rowStart: 0,
                  rowEnd: 1,
                  columnStart: 0,
                  columnEnd: 1,
                ),
              ],
            ),
          ],
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(260, 240));
    final image = await recorder.endRecording().toImage(260, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    final redBounds = _pixelBounds(
      bytes!,
      image.width,
      const Rect.fromLTWH(0, 0, 260, 240),
      _isRedPixel,
    );
    expect(redBounds, isNotNull);
    final bounds = redBounds!;
    final innerColumnEdge = bounds.left + bounds.width / 2;
    final innerRowEdge = bounds.top + bounds.height / 2;

    expect(
      _countPixels(
        bytes,
        image.width,
        Rect.fromLTRB(
          bounds.right - 6,
          bounds.top + 3,
          bounds.right,
          bounds.bottom - 3,
        ),
        _isRedPixel,
      ),
      greaterThan(40),
    );
    expect(
      _countPixels(
        bytes,
        image.width,
        Rect.fromLTRB(
          bounds.left + 3,
          bounds.bottom - 6,
          bounds.right - 3,
          bounds.bottom,
        ),
        _isRedPixel,
      ),
      greaterThan(80),
    );
    expect(
      _countPixels(
        bytes,
        image.width,
        Rect.fromLTRB(
          innerColumnEdge - 2,
          bounds.top + 3,
          innerColumnEdge + 2,
          bounds.bottom - 3,
        ),
        _isRedPixel,
      ),
      0,
    );
    expect(
      _countPixels(
        bytes,
        image.width,
        Rect.fromLTRB(
          bounds.left + 3,
          innerRowEdge - 2,
          bounds.right - 3,
          innerRowEdge + 2,
        ),
        _isRedPixel,
      ),
      0,
    );
  });

