      _countPixels(
        bytes,
        image.width,
        Rect.fromLTRB(
          bounds.left,
          bounds.top + 2,
          bounds.left + 3,
          bounds.bottom - 2,
        ),
        _isRedPixel,
      ),
      greaterThan(15),
    );
    expect(
      _countPixels(
        bytes,
        image.width,
        Rect.fromLTRB(
          bounds.left,
          bounds.top + 2,
          bounds.left + 3,
          bounds.bottom - 2,
        ),
        _isDarkTextPixel,
      ),
      0,
    );
  });

