  test('toolbar popup draws scroll direction indicators', () async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );
    const size = Size(1688, 160);
    final naturalHeight = fortuneToolbarPopupHeightFor(
      fortuneToolbarFormatCommand,
      fortuneToolbarFormatCommands,
    );
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    expect(visibleHeight, lessThan(naturalHeight));

    Future<ByteData> renderPopup(double toolbarPopupScrollOffset) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        toolbarPopupKey: fortuneToolbarFormatCommand,
        toolbarPopupScrollOffset: toolbarPopupScrollOffset,
      ).paint(canvas, size);
      final image = await recorder.endRecording().toImage(
        size.width.toInt(),
        size.height.toInt(),
      );
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);
      expect(bytes, isNotNull);
      return bytes!;
    }

    final topIndicatorRect = Rect.fromLTWH(
      0,
      fortuneToolbarPopupTop + 2,
      size.width,
      fortuneToolbarPopupScrollIndicatorInset +
          fortuneToolbarPopupScrollIndicatorHeight +
          2,
    );
    final bottomIndicatorRect = Rect.fromLTWH(
      0,
      fortuneToolbarPopupTop +
          visibleHeight -
          fortuneToolbarPopupScrollIndicatorInset -
          fortuneToolbarPopupScrollIndicatorHeight -
          2,
      size.width,
      fortuneToolbarPopupScrollIndicatorInset +
          fortuneToolbarPopupScrollIndicatorHeight +
          2,
    );

    final initialBytes = await renderPopup(0);
    expect(
      _countPixels(
        initialBytes,
        size.width.toInt(),
        topIndicatorRect,
        _isToolbarPopupScrollIndicatorPixel,
      ),
      lessThan(5),
    );
    expect(
      _countPixels(
        initialBytes,
        size.width.toInt(),
        bottomIndicatorRect,
        _isToolbarPopupScrollIndicatorPixel,
      ),
      greaterThan(10),
    );

    final scrolledBytes = await renderPopup(90);
    expect(
      _countPixels(
        scrolledBytes,
        size.width.toInt(),
        topIndicatorRect,
        _isToolbarPopupScrollIndicatorPixel,
      ),
      greaterThan(10),
    );
    expect(
      _countPixels(
        scrolledBytes,
        size.width.toInt(),
        bottomIndicatorRect,
        _isToolbarPopupScrollIndicatorPixel,
      ),
      greaterThan(10),
    );
  });

