  test('toolbar popup skips hover fill under scroll indicators', () async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );
    const size = Size(1688, 160);
    final naturalHeight = fortuneToolbarPopupHeightFor(
      fortuneToolbarBorderPopupKey,
      fortuneToolbarBorderPopupCommands,
    );
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final maxScrollOffset = naturalHeight - visibleHeight;
    expect(maxScrollOffset, greaterThan(0));

    final borderItemRect = fortuneVisibleToolbarItemRects(
      size.width,
    ).firstWhere((entry) => entry.key == fortuneToolbarBorderPopupKey).value;
    final popupWidth = fortuneToolbarPopupWidthFor(
      fortuneToolbarBorderPopupKey,
    );
    final popupLeft = fortuneToolbarPopupLeftFor(
      key: fortuneToolbarBorderPopupKey,
      itemRect: borderItemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final hoveredIndex = fortuneToolbarBorderPopupCommands.indexOf(
      fortuneToolbarBorderColorSubmenuKey,
    );
    var hoveredRowTop =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPaddingFor(fortuneToolbarBorderPopupKey);
    for (var index = 0; index < hoveredIndex; index += 1) {
      hoveredRowTop += fortuneToolbarBorderPopupCommands[index] == '|'
          ? fortuneToolbarMenuDividerHeight
          : fortuneToolbarPopupRowHeightFor(fortuneToolbarBorderPopupKey);
    }
    final topIndicatorContentBottom =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupScrollIndicatorInset +
        fortuneToolbarPopupScrollIndicatorHeight +
        fortuneToolbarPopupScrollIndicatorContentGap;
    final scrollOffset = math.min(
      maxScrollOffset,
      hoveredRowTop - topIndicatorContentBottom + 4,
    );

    Future<ByteData> render({int? hoveredIndex}) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        toolbarPopupKey: fortuneToolbarBorderPopupKey,
        toolbarPopupScrollOffset: scrollOffset,
        toolbarBorderHoveredTopLevelIndex: hoveredIndex,
      ).paint(canvas, size);
      final image = await recorder.endRecording().toImage(
        size.width.toInt(),
        size.height.toInt(),
      );
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);
      expect(bytes, isNotNull);
      return bytes!;
    }

    final baselineBytes = await render();
    final hoveredBytes = await render(hoveredIndex: hoveredIndex);

    final topIndicatorGutter = Rect.fromLTWH(
      popupLeft,
      fortuneToolbarPopupTop,
      popupWidth,
      fortuneToolbarPopupScrollIndicatorInset +
          fortuneToolbarPopupScrollIndicatorHeight +
          fortuneToolbarPopupScrollIndicatorContentGap +
          8,
    );
    expect(
      _countChangedPixels(
        baselineBytes,
        hoveredBytes,
        size.width.toInt(),
        topIndicatorGutter,
      ),
      0,
    );
  });

  test('header render hooks receive labels and bounds', () {
    final calls = <Map<String, Object?>>[];
    Canvas? activeCanvas;
    final workbook = FortuneWorkbook(
      settings: FortuneSettings(
        row: 1,
        column: 1,
        beforeRenderColumnHeaderCell:
            (columnChar, columnIndex, left, width, height, hookCanvas) {
              calls.add({
                'hook': 'beforeColumn',
                'label': columnChar,
                'index': columnIndex,
                'left': left,
                'width': width,
                'height': height,
                'sameCanvas': identical(hookCanvas, activeCanvas),
              });
              return true;
            },
        afterRenderColumnHeaderCell:
            (columnChar, columnIndex, left, width, height, hookCanvas) {
              calls.add({
                'hook': 'afterColumn',
                'label': columnChar,
                'index': columnIndex,
                'left': left,
                'width': width,
                'height': height,
                'sameCanvas': identical(hookCanvas, activeCanvas),
              });
            },
        beforeRenderRowHeaderCell:
            (rowNumber, rowIndex, top, width, height, hookCanvas) {
              calls.add({
                'hook': 'beforeRow',
                'label': rowNumber,
                'index': rowIndex,
                'top': top,
                'width': width,
                'height': height,
                'sameCanvas': identical(hookCanvas, activeCanvas),
              });
              return true;
            },
        afterRenderRowHeaderCell:
            (rowNumber, rowIndex, top, width, height, hookCanvas) {
              calls.add({
                'hook': 'afterRow',
                'label': rowNumber,
                'index': rowIndex,
                'top': top,
                'width': width,
                'height': height,
                'sameCanvas': identical(hookCanvas, activeCanvas),
              });
            },
      ),
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    activeCanvas = canvas;
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(220, 160));
    recorder.endRecording();
    activeCanvas = null;

    expect(calls, [
      {
        'hook': 'beforeColumn',
        'label': 'A',
        'index': 0,
        'left': 46.0,
        'width': 74.0,
        'height': 19.0,
        'sameCanvas': true,
      },
      {
        'hook': 'afterColumn',
        'label': 'A',
        'index': 0,
        'left': 46.0,
        'width': 74.0,
        'height': 19.0,
        'sameCanvas': true,
      },
      {
        'hook': 'beforeRow',
        'label': '1',
        'index': 0,
        'top': 20.0,
        'width': 45.0,
        'height': 20.0,
        'sameCanvas': true,
      },
      {
        'hook': 'afterRow',
        'label': '1',
        'index': 0,
        'top': 20.0,
        'width': 45.0,
        'height': 20.0,
        'sameCanvas': true,
      },
    ]);
  });

  test('cut copied range renders dashed outline', () async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
      copiedCellRange: const FortuneRange(
        rowStart: 0,
        rowEnd: 0,
        columnStart: 0,
        columnEnd: 0,
      ),
      copiedCellsAreCut: true,
    ).paint(canvas, const Size(220, 160));
    final image = await recorder.endRecording().toImage(220, 160);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);

    var cutPixels = 0;
    for (var y = 88; y < 112; y += 1) {
      for (var x = 44; x < 122; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 230 && green > 150 && blue < 40) {
          cutPixels += 1;
        }
      }
    }

    expect(cutPixels, greaterThan(20));
  });

