            name: 'Sheet1',
            rowCount: 3,
            columnCount: 3,
            hiddenRows: const {1},
            hiddenColumns: const {1},
            showGridLines: false,
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(
                value: 'visible red',
                background: Color(0xffff0000),
              ),
              const FortuneCellCoord(1, 0): const FortuneCell(
                value: 'hidden row',
                background: Color(0xffff00ff),
              ),
              const FortuneCellCoord(0, 1): const FortuneCell(
                value: 'hidden column',
                background: Color(0xffff00ff),
              ),
              const FortuneCellCoord(2, 0): const FortuneCell(
                value: 'visible blue',
                background: Color(0xff0000ff),
              ),
              const FortuneCellCoord(0, 2): const FortuneCell(
                value: 'visible cyan',
                background: Color(0xff00ffff),
              ),
            },
          ),
        ],
      );

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(260, 180));
      final image = await recorder.endRecording().toImage(260, 180);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);

      int countPixels(
        Rect rect,
        bool Function(int red, int green, int blue) test,
      ) {
        var pixels = 0;
        for (var y = rect.top.floor(); y < rect.bottom.ceil(); y += 1) {
          for (var x = rect.left.floor(); x < rect.right.ceil(); x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (test(red, green, blue)) {
              pixels += 1;
            }
          }
        }
        return pixels;
      }

      final bluePixels = countPixels(
        const Rect.fromLTWH(48, 112, 68, 16),
        (red, green, blue) => red < 40 && green < 40 && blue > 220,
      );
      final cyanPixels = countPixels(
        const Rect.fromLTWH(122, 92, 68, 16),
        (red, green, blue) => red < 40 && green > 220 && blue > 220,
      );
      final hiddenMagentaPixels = countPixels(
        const Rect.fromLTWH(46, 90, 150, 40),
        (red, green, blue) => red > 220 && green < 40 && blue > 220,
      );

      expect(bluePixels, greaterThan(150));
      expect(cyanPixels, greaterThan(300));
      expect(hiddenMagentaPixels, lessThan(4));
    },
  );

  test('frozen panes render row and column guide lines', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          defaultRowHeight: 40,
          defaultColWidth: 50,
          showGridLines: false,
          frozen: const FortuneFrozenPane(
            type: 'rangeBoth',
            rowFocus: 1,
            columnFocus: 1,
          ),
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(320, 240));
    final image = await recorder.endRecording().toImage(320, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);

    int guidePixels(Rect rect) {
      var pixels = 0;
      for (var y = rect.top.floor(); y < rect.bottom.ceil(); y += 1) {
        for (var x = rect.left.floor(); x < rect.right.ceil(); x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red >= 160 &&
              red <= 205 &&
              (red - green).abs() <= 3 &&
              (red - blue).abs() <= 3) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    expect(guidePixels(const Rect.fromLTWH(145, 92, 4, 88)), greaterThan(70));
    expect(guidePixels(const Rect.fromLTWH(54, 170, 190, 4)), greaterThan(120));
  });

