      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      freezeDragLineX: 90,
      freezeDragLineY: 50,
      resizeDragLineX: 130,
      resizeDragLineY: 80,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(260, 220));
    final image = await recorder.endRecording().toImage(260, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);

    int countPixels(
      Rect rect,
      bool Function(int red, int green, int blue) test,
    ) {
      var pixels = 0;
      for (var y = rect.top.floor(); y < rect.bottom.ceil(); y += 1) {
        for (var x = rect.left.floor(); x < rect.right.ceil(); x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (test(red, green, blue)) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final freezeVerticalPixels = countPixels(
      const Rect.fromLTWH(88, 76, 5, 88),
      (red, green, blue) =>
          (red - 0xcc).abs() <= 2 &&
          (green - 0xcc).abs() <= 2 &&
          (blue - 0xcc).abs() <= 2,
    );
    final freezeHorizontalPixels = countPixels(
      const Rect.fromLTWH(12, 118, 232, 5),
      (red, green, blue) =>
          (red - 0xcc).abs() <= 2 &&
          (green - 0xcc).abs() <= 2 &&
          (blue - 0xcc).abs() <= 2,
    );
    final resizeVerticalPixels = countPixels(
      const Rect.fromLTWH(128, 76, 5, 88),
      (red, green, blue) => red < 170 && green > 100 && blue > 180,
    );
    final resizeHorizontalPixels = countPixels(
      const Rect.fromLTWH(12, 148, 232, 5),
      (red, green, blue) => red < 170 && green > 100 && blue > 180,
    );

    expect(freezeVerticalPixels, greaterThan(120));
    expect(freezeHorizontalPixels, greaterThan(300));
    expect(resizeVerticalPixels, greaterThan(50));
    expect(resizeHorizontalPixels, greaterThan(120));
  });

