  test('raw chart overlays render line end labels', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'lineEndLabel',
                'left': 20,
                'top': 20,
                'width': 170,
                'height': 110,
                'option': {
                  'series': [
                    {
                      'type': 'line',
                      'showSymbol': false,
                      'lineStyle': {'color': '#0000ff', 'width': 2},
                      'endLabel': {
                        'show': true,
                        'color': '#00aa00',
                        'backgroundColor': '#00ff00',
                        'fontSize': 18,
                        'fontWeight': 'bold',
                        'formatter': 'END {c}',
                      },
                      'data': [1, 2, 4],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    final series = overlay.chartSeries.single;
    expect(series.endLabelShow, isTrue);
    expect(series.endLabelColor, const Color(0xff00aa00));
    expect(series.endLabelFormatter, 'END {c}');
    expect(series.values, [1, 2, 4]);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      const Rect.fromLTWH(20, 20, 170, 110),
      overlay,
      const Rect.fromLTWH(0, 0, 260, 180),
    );
    final image = await recorder.endRecording().toImage(260, 180);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var greenTextPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (green > red + 12 && green > blue + 12 && green > 100) {
          greenTextPixels += 1;
        }
      }
    }
    expect(greenTextPixels, greaterThan(8));
  });

