  test('raw chart overlays render pie and area series', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'pie1',
                'left': 20,
                'top': 20,
                'width': 90,
                'height': 70,
                'option': {
                  'series': [
                    {
                      'type': 'pie',
                      'data': [2, 3, 4],
                    },
                  ],
                },
              },
              {
                'id': 'area1',
                'left': 130,
                'top': 20,
                'width': 100,
                'height': 70,
                'option': {
                  'series': [
                    {
                      'type': 'area',
                      'data': [1, 5, 2, 6],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays.map((overlay) => overlay.chartSeries.first.type), [
      'pie',
      'area',
    ]);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(360, 240));
    final image = await recorder.endRecording().toImage(360, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var pieGreenPixels = 0;
    var areaBluePixels = 0;
    for (var y = 112; y < 174; y += 1) {
      for (var x = 72; x < 276; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (green > red + 40 && green > blue + 20) {
          pieGreenPixels += 1;
        }
        if (blue > red + 45 && blue > green + 10) {
          areaBluePixels += 1;
        }
      }
    }
    expect(pieGreenPixels, greaterThan(0));
    expect(areaBluePixels, greaterThan(0));
  });

