    expect(series.endLabelRichStyles['tail']?.fontWeight, FontWeight.w700);
    expect(series.endLabelTextBorderColor, const Color(0xff3a3b3c));
    expect(series.endLabelTextBorderWidth, 1);
    expect(series.endLabelTextBorderType, 'dotted');
    expect(series.endLabelTextShadowColor, const Color(0xff3d3e3f));
    expect(series.endLabelTextShadowBlur, 7);
    expect(series.endLabelTextShadowOffsetX, 8);
    expect(series.endLabelTextShadowOffsetY, -9);
    expect(series.endLabelFontSize, 16);
    expect(series.endLabelPosition, 'inside');
    expect(series.endLabelFormatter, '{b}: {c}');
    expect(series.symbolSize, 14);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(280, 240));
    final image = await recorder.endRecording().toImage(280, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var magentaLeft = image.width;
    var magentaRight = 0;
    var cyanGraphicPixels = 0;
    for (var y = 100; y < 190; y += 1) {
      for (var x = 55; x < 175; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaPixels += 1;
          magentaLeft = math.min(magentaLeft, x);
          magentaRight = math.max(magentaRight, x);
        }
        if (green > 180 && blue > 180 && red < 80) {
          cyanGraphicPixels += 1;
        }
      }
    }
    expect(magentaPixels, greaterThan(110));
    expect(magentaRight - magentaLeft, greaterThan(60));
    expect(cyanGraphicPixels, greaterThan(110));
  });

