  test('raw chart overlays parse scatter array data points', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'scatterArrayPoints',
                'left': 20,
                'top': 20,
                'width': 130,
                'height': 90,
                'option': {
                  'series': [
                    {
                      'type': 'scatter',
                      'symbolSize': 14,
                      'itemStyle': {'color': '#ff00ff'},
                      'data': [
                        [0, 1],
                        [10, 5],
                        [100, 2],
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final series = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).single.chartSeries.single;
    expect(series.values, [1, 5, 2]);
    expect(series.valueSlots, [1, 5, 2]);
    expect(series.xValueSlots, [0, 10, 100]);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(280, 240));
    final image = await recorder.endRecording().toImage(280, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var centerBandMagentaPixels = 0;
    for (var y = 100; y < 190; y += 1) {
      for (var x = 55; x < 175; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaPixels += 1;
          if (x >= 100 && x < 122) {
            centerBandMagentaPixels += 1;
          }
        }
      }
    }
    expect(magentaPixels, greaterThan(120));
    expect(centerBandMagentaPixels, lessThan(30));
  });

  test('raw chart dataset row layout supplies series values', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'datasetRowLayoutBars',
                'left': 20,
                'top': 20,
                'width': 160,
                'height': 110,
                'option': {
                  'yAxis': {'min': 0, 'max': 6},
                  'dataset': {
                    'sourceHeader': 1,
                    'seriesLayoutBy': 'row',
                    'source': [
                      ['name', 'A', 'B', 'C'],
                      ['actual', 1, 5, 1],
                    ],
                  },
                  'series': [
                    {
                      'type': 'bar',
                      'itemStyle': {'color': '#ff00ff', 'opacity': 1},
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartSeries.single.values, [1, 5, 1]);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(240, 220));
    final image = await recorder.endRecording().toImage(240, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    for (var y = 20; y < image.height; y += 1) {
      for (var x = 20; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaPixels += 1;
        }
      }
    }
    expect(magentaPixels, greaterThan(150));
  });

