    var indexedCyanPixels = 0;
    for (var y = 145; y < 180; y += 1) {
      for (var x = 120; x < 280; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (green > 180 && blue > 180 && red < 100) {
          if (x >= 190) {
            rightCyanPixels += 1;
          } else {
            indexedCyanPixels += 1;
          }
        }
      }
    }

    expect(rightCyanPixels, greaterThan(1200));
    expect(indexedCyanPixels, lessThan(10));
