      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red <= 180 || green >= 80 || blue >= 80) {
          continue;
        }
        minRedX = math.min(minRedX, x);
        maxRedX = math.max(maxRedX, x);
        minRedY = math.min(minRedY, y);
        maxRedY = math.max(maxRedY, y);
      }
    }
    expect(minRedX, inInclusiveRange(145, 148));
    expect(maxRedX, inInclusiveRange(184, 187));
