    var bluePixels = 0;
    var centerGreenPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isGreen = green > 180 && red < 80 && blue < 80;
        if (isGreen) {
          greenPixels += 1;
          if (x >= 135 && x < 158 && y >= 140 && y < 164) {
            centerGreenPixels += 1;
          }
        }
        if (blue > 180 && red < 80 && green < 80) {
          bluePixels += 1;
        }
      }
    }
    expect(greenPixels, greaterThan(350));
    expect(bluePixels, greaterThan(120));

    expect(centerGreenPixels, lessThan(80));
  });

