                      'height': 16,
                      'children': [
                        {
                          'type': 'rect',
                          'shape': {'width': 54, 'height': 16},
                          'style': {'fill': '#ff0000'},
                        },
                      ],
                    },
                    {
                      'type': 'group',
                      'x': 138,
                      'y': 36,
                      'width': 54,
                      'height': 16,
                      'origin': ['50%', '50%'],
                      'rotation': 1.5707963267948966,
                      'children': [
                        {
                          'type': 'rect',
                          'shape': {'width': 54, 'height': 16},
                          'style': {'fill': '#0000ff'},
                        },
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(320, 240));
    final image = await recorder.endRecording().toImage(320, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var minRedX = image.width;
    var maxRedX = 0;
    var minRedY = image.height;
    var maxRedY = 0;
    var minBlueX = image.width;
    var maxBlueX = 0;
    var minBlueY = image.height;
    var maxBlueY = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && green < 80 && blue < 80) {
          minRedX = math.min(minRedX, x);
          maxRedX = math.max(maxRedX, x);
          minRedY = math.min(minRedY, y);
          maxRedY = math.max(maxRedY, y);
        }
        if (blue > 180 && red < 80 && green < 80) {
          minBlueX = math.min(minBlueX, x);
          maxBlueX = math.max(maxBlueX, x);
          minBlueY = math.min(minBlueY, y);
          maxBlueY = math.max(maxBlueY, y);
        }
      }
    }

    final redWidth = maxRedX - minRedX + 1;
    final redHeight = maxRedY - minRedY + 1;
    final blueWidth = maxBlueX - minBlueX + 1;
    final blueHeight = maxBlueY - minBlueY + 1;
    expect(redWidth, greaterThan(45));
    expect(redWidth, greaterThan(redHeight * 2));
    expect(blueHeight, greaterThan(45));
    expect(blueHeight, greaterThan(blueWidth * 2));
  });

