  test(
    'raw chart overlays honor graphic lowercase shape line dash offsets',
    () async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: const {
              'chart': [
                {
                  'id': 'graphicLowercaseShapeDashOffset',
                  'left': 20,
                  'top': 20,
                  'width': 190,
                  'height': 240,
                  'option': {
                    'graphic': [
                      {
                        'type': 'rect',
                        'x': 68,
                        'y': 28,
                        'shape': {'width': 80, 'height': 40},
                        'style': {
                          'stroke': '#ff0000',
                          'lineWidth': 4,
                          'linedash': [8, 8],
                        },
                      },
                      {
                        'type': 'rect',
                        'x': 68,
                        'y': 92,
                        'shape': {'width': 80, 'height': 40},
                        'style': {
                          'stroke': '#0000ff',
                          'lineWidth': 4,
                          'linedash': [8, 8],
                          'linedashoffset': 8,
                        },
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(280, 340));
      final image = await recorder.endRecording().toImage(280, 340);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var redTopY = image.height;
      var blueTopY = image.height;
      var redLeftX = image.width;
      var redRightX = -1;
      var blueLeftX = image.width;
      var blueRightX = -1;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green < 80 && blue < 80) {
            redTopY = math.min(redTopY, y);
            redLeftX = math.min(redLeftX, x);
            redRightX = math.max(redRightX, x);
          }
          if (blue > 180 && red < 80 && green < 80) {
            blueTopY = math.min(blueTopY, y);
            blueLeftX = math.min(blueLeftX, x);
            blueRightX = math.max(blueRightX, x);
          }
        }
      }

      var redPixels = 0;
      var bluePixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (y >= redTopY && y < redTopY + 6) {
            if (red > 180 && green < 80 && blue < 80) {
              redPixels += 1;
            }
          }
          if (y >= blueTopY && y < blueTopY + 6) {
            if (blue > 180 && red < 80 && green < 80) {
              bluePixels += 1;
            }
          }
        }
      }

      bool redTopEdgeHit(int relativeX) {
        for (var dy = 0; dy < 6; dy += 1) {
          final x = redLeftX + relativeX;
          final y = redTopY + dy;
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green < 80 && blue < 80) {
            return true;
          }
        }
        return false;
      }

      bool blueTopEdgeHit(int relativeX) {
        for (var dy = 0; dy < 6; dy += 1) {
          final x = blueLeftX + relativeX;
          final y = blueTopY + dy;
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (blue > 180 && red < 80 && green < 80) {
            return true;
          }
        }
        return false;
      }

      final sharedWidth = math.min(
        redRightX - redLeftX,
        blueRightX - blueLeftX,
      );
      var mismatchedColumns = 0;
      for (var relativeX = 8; relativeX < sharedWidth - 8; relativeX += 1) {
        if (redTopEdgeHit(relativeX) != blueTopEdgeHit(relativeX)) {
          mismatchedColumns += 1;
        }
      }

      expect(redPixels, greaterThan(20));
      expect(bluePixels, greaterThan(20));
      expect(mismatchedColumns, greaterThan(12));
    },
  );

