                'width': 180,
                'height': 120,
                'option': {
                  'graphic': [
                    {
                      'type': 'rect',
                      'x': 34,
                      'y': 28,
                      'shape': {'width': 36, 'height': 36},
                      'style': {
                        'fill': '#ff0000',
                        'stroke': '#0000ff',
                        'lineWidth': 14,
                      },
                    },
                    {
                      'type': 'rect',
                      'x': 104,
                      'y': 28,
                      'shape': {'width': 36, 'height': 36},
                      'style': {
                        'fill': '#ff0000',
                        'stroke': '#0000ff',
                        'lineWidth': 14,
                        'strokeFirst': true,
                      },
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(280, 220));
    final image = await recorder.endRecording().toImage(280, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var defaultBluePixels = 0;
    var defaultRedPixels = 0;
    var strokeFirstRedPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isBlue = blue > 180 && red < 80 && green < 80;
        if (isBlue && x < 125) {
          defaultBluePixels += 1;
        }
        if (x < 125 && red > 180 && green < 80 && blue < 80) {
          defaultRedPixels += 1;
        }
        if (x >= 125 && red > 180 && green < 80 && blue < 80) {
          strokeFirstRedPixels += 1;
        }
      }
    }
    expect(defaultBluePixels, greaterThan(200));
    expect(defaultRedPixels, lessThan(220));
    expect(strokeFirstRedPixels, greaterThan(defaultRedPixels + 120));
  });

