  test('raw chart overlays honor graphic text alignment', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'graphicTextAlignment',
                'left': 20,
                'top': 20,
                'width': 180,
                'height': 120,
                'option': {
                  'graphic': [
                    {
                      'type': 'text',
                      'x': 120,
                      'y': 58,
                      'style': {
                        'text': 'ALIGN',
                        'fill': '#ff0000',
                        'fontSize': 24,
                        'align': 'right',
                        'verticalAlign': 'bottom',
                      },
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(280, 220));
    final image = await recorder.endRecording().toImage(280, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var anchoredPixels = 0;
    var unalignedPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isRed = red > 180 && green < 100 && blue < 100;
        if (!isRed) {
          continue;
        }
        if (x >= 70 && x < 198 && y >= 150 && y < 166) {
          anchoredPixels += 1;
        }
        if (x >= 70 && x < 210 && y >= 166 && y < 190) {
          unalignedPixels += 1;
        }
      }
    }
    expect(anchoredPixels, greaterThan(1000));
    expect(unalignedPixels, lessThan(12));
  });

