      ).paint(canvas, const Size(280, 220));
      final image = await recorder.endRecording().toImage(280, 220);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var magentaPixels = 0;
      var magentaMinY = image.height;
      var magentaMaxY = 0;
      var yellowPixels = 0;
      var yellowMinY = image.height;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 200 && green > 180 && blue < 80) {
            yellowPixels += 1;
            yellowMinY = math.min(yellowMinY, y);
          }
          if (red > 160 && green < 80 && blue > 160) {
            magentaPixels += 1;
            magentaMinY = math.min(magentaMinY, y);
            magentaMaxY = math.max(magentaMaxY, y);
          }
        }
      }
      expect(yellowPixels, greaterThan(700));
      expect(magentaPixels, greaterThan(200));
      expect(magentaMinY, lessThan(yellowMinY));
      expect(magentaMaxY, lessThan(yellowMinY));
    },
  );

