            extraFields: {
              'chart': [
                {
                  'id': 'graphicTextBoxBorderType',
                  'left': 20,
                  'top': 20,
                  'width': 180,
                  'height': 120,
                  'option': {
                    'graphic': [
                      {'type': 'text', 'x': 42, 'y': 40, 'style': style},
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<(int cyanPixels, int magentaPixels)> paintCounts(
      FortuneWorkbook workbook,
    ) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(280, 220));
      final image = await recorder.endRecording().toImage(280, 220);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var cyanPixels = 0;
      var magentaPixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (green > 180 && blue > 180 && red < 100) {
            cyanPixels += 1;
          }
          if (red > 180 && blue > 180 && green < 100) {
            magentaPixels += 1;
          }
        }
      }
      return (cyanPixels, magentaPixels);
    }

    final solid = await paintCounts(workbookFor(null));
    final dashed = await paintCounts(workbookFor('dashed'));

    expect(dashed.$1, greaterThan(250));
    expect(dashed.$2, greaterThan(60));
    expect(dashed.$2, lessThan(solid.$2));
  });

