  test('raw chart overlays render candlestick series', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'candles1',
                'left': 20,
                'top': 20,
                'width': 150,
                'height': 100,
                'option': {
                  'series': [
                    {
                      'type': 'candlestick',
                      'itemStyle': {
                        'color': '#ff00ff',
                        'color0': '#00ffff',
                        'borderColor': '#ff00ff',
                        'borderColor0': '#00ffff',
                      },
                      'data': [
                        [20, 34, 10, 40],
                        [36, 18, 12, 42],
                        [18, 30, 14, 32],
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final series = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).single.chartSeries.single;
    expect(series, isA<FortuneRawChartSeries>());
    expect(series.type, 'candlestick');
    expect(series.values, [34, 18, 30]);
    expect(series.candlestickPoints.length, 3);
    expect(
      series.candlestickPoints.first,
      isA<FortuneRawChartCandlestickPoint>(),
    );
    expect(series.candlestickPoints.first.open, 20);
    expect(series.candlestickPoints.first.close, 34);
    expect(series.candlestickPoints.first.low, 10);
    expect(series.candlestickPoints.first.high, 40);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
