                    },
                    {
                      'type': 'heatmap',
                      'blendMode': 'multiply',
                      'data': [
                        {
                          'value': [0, 0, 1],
                          'itemStyle': {'color': '#ff0000'},
                        },
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(280, 220));
    final image = await recorder.endRecording().toImage(280, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var darkBlendPixels = 0;
    var redPixels = 0;
    for (var y = 60; y < 180; y += 1) {
      for (var x = 40; x < 220; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red < 40 && green < 40 && blue < 40) {
          darkBlendPixels += 1;
        }
        if (red > 220 && green < 40 && blue < 40) {
          redPixels += 1;
        }
      }
    }
    expect(darkBlendPixels, greaterThan(500));
    expect(redPixels, lessThan(80));
  });

