    for (var y = 108; y < 190; y += 1) {
      for (var x = 64; x < 300; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (x < 180 && green > 180 && blue > 180 && red < 100) {
          shownCyanPixels += 1;
        }
        if (x >= 184 && red > 180 && blue > 180 && green < 100) {
          hiddenMagentaPixels += 1;
        }
      }
    }
    expect(shownCyanPixels, greaterThan(20));
    expect(hiddenMagentaPixels, 0);
  });

