  test('raw chart overlays honor pie percent precision labels', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'piePercent0',
                'left': 20,
                'top': 20,
                'width': 100,
                'height': 86,
                'option': {
                  'series': [
                    {
                      'type': 'pie',
                      'percentPrecision': 0,
                      'label': {
                        'show': true,
                        'position': 'center',
                        'color': '#ff00ff',
                        'fontSize': 18,
                        'formatter': '{d}%',
                      },
                      'data': [
                        {'value': 1},
                        {
                          'value': 1,
                          'label': {'show': false},
                        },
                      ],
                    },
                  ],
                },
              },
              {
                'id': 'piePercent2',
                'left': 140,
                'top': 20,
                'width': 100,
                'height': 86,
                'option': {
                  'series': [
                    {
                      'type': 'pie',
                      'percentPrecision': 2,
                      'label': {
                        'show': true,
                        'position': 'center',
                        'color': '#ff00ff',
                        'fontSize': 18,
                        'formatter': '{d}%',
                      },
                      'data': [
                        {'value': 1},
                        {
                          'value': 1,
                          'label': {'show': false},
                        },
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays.first.chartSeries.single.percentPrecision, 0);
    expect(overlays[1].chartSeries.single.percentPrecision, 2);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(280, 230));
    final image = await recorder.endRecording().toImage(280, 230);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var percent0MagentaPixels = 0;
    var percent2MagentaPixels = 0;
    for (var y = 138; y < 176; y += 1) {
      for (var x = 20; x < 280; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isMagenta = red > 180 && blue > 180 && green < 100;
        if (!isMagenta) {
          continue;
        }
        if (x >= 20 && x < 140) {
          percent0MagentaPixels += 1;
        }
        if (x >= 140 && x < 280) {
          percent2MagentaPixels += 1;
        }
      }
    }
    expect(percent0MagentaPixels, greaterThan(10));
    expect(percent2MagentaPixels, greaterThan(percent0MagentaPixels));
  });

