                'height': 110,
                'option': {
                  'series': [
                    {
                      'type': 'pie',
                      'labelLayout': {
                        'width': 104,
                        'height': 44,
                        'align': 'right',
                        'verticalAlign': 'bottom',
                      },
                      'label': {
                        'show': true,
                        'position': 'center',
                        'color': '#00ffff',
                        'backgroundColor': '#ff00ff',
                        'fontSize': 20,
                        'formatter': 'TXT',
                        'align': 'left',
                        'verticalAlign': 'top',
                      },
                      'data': [
                        {'value': 1},
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final series = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).single.chartSeries.single;
    expect(series.labelLayoutAlign, 'right');
    expect(series.labelLayoutVerticalAlign, 'bottom');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(240, 240));
    final image = await recorder.endRecording().toImage(240, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var cyanPixels = 0;
    var magentaLeft = image.width;
    var magentaRight = 0;
    var magentaTop = image.height;
    var magentaBottom = 0;
    var cyanXSum = 0;
    var cyanYSum = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaPixels += 1;
          magentaLeft = math.min(magentaLeft, x);
          magentaRight = math.max(magentaRight, x);
          magentaTop = math.min(magentaTop, y);
          magentaBottom = math.max(magentaBottom, y);
        }
        if (green > 180 && blue > 180 && red < 100) {
          cyanPixels += 1;
          cyanXSum += x;
          cyanYSum += y;
        }
      }
    }
    expect(magentaPixels, greaterThan(2500));
    expect(cyanPixels, greaterThan(20));
    expect(
      cyanXSum / cyanPixels,
      greaterThan((magentaLeft + magentaRight) / 2),
    );
    expect(
      cyanYSum / cyanPixels,
      greaterThan((magentaTop + magentaBottom) / 2),
    );
  });

