  test('raw chart overlays render pie label line smooth curves', () async {
    FortuneWorkbook workbookFor({required bool smooth}) => FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              {
                'id': smooth ? 'pieSmoothLine' : 'pieStraightLine',
                'left': 20,
                'top': 20,
                'width': 130,
                'height': 96,
                'option': {
                  'series': [
                    {
                      'type': 'pie',
                      'startAngle': 45,
                      'label': {
                        'show': true,
                        'position': 'outside',
                        'color': '#000000',
                        'fontSize': 12,
                        'formatter': 'A',
                      },
                      'labelLine': {
                        'show': true,
                        'smooth': false,
                        'length': 22,
                        'length2': 34,
                        'lineStyle': {'color': '#000000', 'width': 1},
                      },
                      'data': [
                        {
                          'value': 1,
                          'labelLine': {
                            'smooth': smooth,
                            'lineStyle': {'color': '#ff00ff', 'width': 4},
                          },
                        },
                        {
                          'value': 1,
                          'label': {'show': false},
                        },
                      ],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    Future<({ui.Image image, ByteData bytes})> paintWorkbook(
      FortuneWorkbook workbook,
    ) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(360, 320));
      final image = await recorder.endRecording().toImage(360, 320);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);
      expect(bytes, isNotNull);
      return (image: image, bytes: bytes!);
    }

    int countMagentaRows(ui.Image image, ByteData bytes, int yStart, int yEnd) {
      var pixels = 0;
      for (var y = yStart; y < yEnd; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 120) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final straightSeries = fortuneRawShapeOverlays(
      workbookFor(smooth: false).activeSheet,
    ).single.chartSeries.single;
    final smoothSeries = fortuneRawShapeOverlays(
      workbookFor(smooth: true).activeSheet,
    ).single.chartSeries.single;
    expect(straightSeries.pointLabelLineSmooths.first, isFalse);
    expect(smoothSeries.pointLabelLineSmooths.first, isTrue);

    final straight = await paintWorkbook(workbookFor(smooth: false));
    final smooth = await paintWorkbook(workbookFor(smooth: true));
    final straightShoulder = countMagentaRows(
      straight.image,
      straight.bytes,
      189,
      192,
    );
    final smoothShoulder = countMagentaRows(
      smooth.image,
      smooth.bytes,
      189,
      192,
    );
    final straightTail = countMagentaRows(
      straight.image,
      straight.bytes,
      192,
      196,
    );
    final smoothTail = countMagentaRows(smooth.image, smooth.bytes, 192, 196);

    expect(smoothShoulder, greaterThan(straightShoulder + 15));
    expect(straightTail, greaterThan(smoothTail + 35));
  });

