  test('raw chart overlays honor non-pie series label positions', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'barInsideLabel',
                'left': 20,
                'top': 20,
                'width': 120,
                'height': 90,
                'option': {
                  'series': [
                    {
                      'type': 'bar',
                      'data': [5],
                      'itemStyle': {'color': '#808080'},
                      'label': {
                        'show': true,
                        'position': 'inside',
                        'color': '#ff00ff',
                        'fontSize': 18,
                        'formatter': 'AA',
                      },
                    },
                  ],
                },
              },
              {
                'id': 'barOutsideLabel',
                'left': 160,
                'top': 20,
                'width': 120,
                'height': 90,
                'option': {
                  'series': [
                    {
                      'type': 'bar',
                      'data': [5],
                      'itemStyle': {'color': '#808080'},
                      'label': {
                        'show': true,
                        'position': 'outside',
                        'distance': 28,
                        'color': '#00ffff',
                        'fontSize': 18,
                        'formatter': 'AA',
                      },
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final chartSeries = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).expand((overlay) => overlay.chartSeries).toList();
    expect(chartSeries.first.labelPosition, 'inside');
    expect(chartSeries.last.labelPosition, 'outside');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(340, 240));
    final image = await recorder.endRecording().toImage(340, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    ({int minY, int maxY, int pixels}) colorBounds(
      bool Function(int red, int green, int blue) matches,
    ) {
      var minY = image.height;
      var maxY = 0;
      var pixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            pixels += 1;
            if (y < minY) {
              minY = y;
            }
            if (y > maxY) {
              maxY = y;
            }
          }
        }
      }
      return (minY: minY, maxY: maxY, pixels: pixels);
    }

    final insideLabel = colorBounds(
      (red, green, blue) => red > 180 && blue > 180 && green < 120,
    );
    final outsideLabel = colorBounds(
      (red, green, blue) => green > 180 && blue > 180 && red < 120,
    );

    expect(insideLabel.pixels, greaterThan(20));
    expect(outsideLabel.pixels, greaterThan(20));
    expect(outsideLabel.maxY, lessThan(insideLabel.minY));
  });

