    expect(overlay.chartDataZoomEndPercent, 75);
    expect(overlay.chartDataZoomBackgroundColor, const Color(0xffeeeeee));
    expect(overlay.chartDataZoomFillerColor, const Color(0xffff00ff));
    expect(overlay.chartDataZoomHandleColor, const Color(0xff00ff00));
    expect(overlay.chartDataZoomBorderColor, const Color(0xff0000ff));
    expect(overlay.chartDataZoomBorderWidth, 2);
    expect(overlay.chartDataZoomBorderType, 'dashed');
    expect(overlay.chartDataZoomSize, 12);
    expect(overlay.chartDataZoomHandleSize, 20);
    expect(overlay.chartDataZoomHandleBorderColor, const Color(0xffff0000));
    expect(overlay.chartDataZoomHandleBorderWidth, 2);
    expect(overlay.chartDataZoomHandleBorderType, 'dotted');
    expect(overlay.chartDataZoomHandleShadowColor, const Color(0xff00ffff));
    expect(overlay.chartDataZoomHandleShadowBlur, 0);
    expect(overlay.chartDataZoomHandleShadowOffsetY, 12);
    expect(overlay.chartDataZoomHandleOpacity, closeTo(0.75, 0.001));
    expect(overlay.chartDataZoomFilterMode, 'weakFilter');
    expect(overlay.chartDataZoomZoomLock, isTrue);
    expect(overlay.chartDataZoomRealtime, isFalse);
    expect(overlay.chartDataZoomShowDetail, isFalse);
    expect(overlay.chartDataZoomShowDataShadow, 'auto');
    expect(overlay.chartDataZoomBrushSelect, isTrue);
    expect(overlay.chartDataZoomThrottle, 80);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      overlay.rect,
      overlay,
      const Rect.fromLTWH(0, 0, 360, 240),
    );
    final image = await recorder.endRecording().toImage(360, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var greenPixels = 0;
    var bluePixels = 0;
    var redPixels = 0;
    var cyanPixels = 0;
    var dataShadowPixels = 0;
    var backgroundPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red >= 225 &&
            red <= 245 &&
            green >= 225 &&
            green <= 245 &&
            blue >= 225 &&
            blue <= 245 &&
            (red - green).abs() <= 2 &&
            (green - blue).abs() <= 2) {
          backgroundPixels += 1;
        }
        if (red > 180 && blue > 180 && green < 100) {
          magentaPixels += 1;
        }
        if (green > 180 && red < 100 && blue < 100) {
          greenPixels += 1;
        }
        if (blue > 180 && red < 100 && green < 100) {
          bluePixels += 1;
        }
        if (red > 180 && green < 100 && blue < 100) {
          redPixels += 1;
        }
        if (green > 180 && blue > 180 && red < 100) {
          cyanPixels += 1;
        }
        if (red > 90 &&
            red < 150 &&
            green > 120 &&
            green < 170 &&
            blue > 130 &&
            blue < 180) {
          dataShadowPixels += 1;
        }
      }
    }
    expect(magentaPixels, greaterThan(20));
    expect(greenPixels, greaterThan(10));
    expect(bluePixels, greaterThan(20));
    expect(redPixels, greaterThan(10));
    expect(cyanPixels, greaterThan(10));
    expect(dataShadowPixels, greaterThan(20));
    expect(backgroundPixels, greaterThan(20));
  });

