  test('raw chart overlays honor data zoom handle border types', () async {
    Map<String, Object?> chart(String id, int left, String? borderType) {
      final handleStyle = <String, Object?>{
        'color': '#0000ff',
        'borderColor': '#ff0000',
        'borderWidth': 3,
      };
      if (borderType != null) {
        handleStyle['borderType'] = borderType;
      }
      return {
        'id': id,
        'left': left,
        'top': 20,
        'width': 150,
        'height': 100,
        'option': {
          'dataZoom': {
            'show': true,
            'start': 30,
            'end': 70,
            'height': 14,
            'handleSize': 28,
            'showDetail': false,
            'backgroundColor': '#eeeeee',
            'fillerColor': '#00ff00',
            'handleStyle': handleStyle,
          },
          'series': [
            {
              'type': 'line',
              'showSymbol': false,
              'data': [1, 4, 2, 5, 3, 6],
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('solidDataZoomHandleBorder', 20, null),
              chart('dashedDataZoomHandleBorder', 210, 'dashed'),
              chart('dottedDataZoomHandleBorder', 400, 'dotted'),
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays[0].chartDataZoomHandleBorderType, isNull);
    expect(overlays[1].chartDataZoomHandleBorderType, 'dashed');
    expect(overlays[2].chartDataZoomHandleBorderType, 'dotted');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(620, 240));
    final image = await recorder.endRecording().toImage(620, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    int redPixelsIn(int left, int right) {
      var pixels = 0;
      for (var y = 120; y < 200; y += 1) {
        for (var x = left; x < right; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green < 100 && blue < 100) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final solidRedPixels = redPixelsIn(20, 170);
    final dashedRedPixels = redPixelsIn(210, 360);
    final dottedRedPixels = redPixelsIn(400, 550);

    expect(solidRedPixels, greaterThan(50));
    expect(dashedRedPixels, greaterThan(20));
    expect(dottedRedPixels, greaterThan(20));
    expect(dashedRedPixels, lessThan(solidRedPixels * 0.6));
    expect(dottedRedPixels, lessThan(solidRedPixels * 0.6));
  });

