  test('raw chart overlays honor visual map calculable handles', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'visualMapCalculable',
                'left': 20,
                'top': 20,
                'width': 150,
                'height': 110,
                'option': {
                  'visualMap': {
                    'show': true,
                    'calculable': 'true',
                    'inRange': {
                      'color': ['#0000ff', '#ff0000'],
                    },
                  },
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartVisualMapCalculable, isTrue);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      overlay.rect,
      overlay,
      const Rect.fromLTWH(0, 0, 280, 240),
    );
    final image = await recorder.endRecording().toImage(280, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    final barRect = Rect.fromLTWH(
      overlay.rect.right - 19,
      overlay.rect.top + math.max(8.0, overlay.rect.height * 0.22),
      8,
      math.max(20.0, overlay.rect.height * 0.42),
    );

    int grayHandlePixels(Rect sample) {
      var pixels = 0;
      for (var y = sample.top.floor(); y <= sample.bottom.ceil(); y += 1) {
        for (var x = sample.left.floor(); x <= sample.right.ceil(); x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 120 &&
              red < 210 &&
              (red - green).abs() < 18 &&
              (green - blue).abs() < 18) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final topHandlePixels = grayHandlePixels(
      Rect.fromCenter(
        center: Offset(barRect.center.dx, barRect.top),
        width: 13,
        height: 13,
      ),
    );
    final bottomHandlePixels = grayHandlePixels(
      Rect.fromCenter(
        center: Offset(barRect.center.dx, barRect.bottom),
        width: 13,
        height: 13,
      ),
    );

    expect(topHandlePixels, greaterThan(4));
    expect(bottomHandlePixels, greaterThan(4));
  });

