                'width': 120,
                'height': 90,
                'option': {
                  'xAxis': {
                    'data': ['Start', 'Middle', 'End'],
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2],
                      'lineStyle': {'color': '#000000', 'width': 1},
                      'markLine': {
                        'symbol': [' Circle ', 'TRIANGLE'],
                        'symbolSize': [24, 28],
                        'lineStyle': {'color': '#00ffff', 'width': 1},
                        'data': [
                          {'xAxis': 'Middle'},
                        ],
                      },
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final markLine = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).single.chartSeries.single.markLines.single;
    expect(markLine.xIndex, 1);
    expect(markLine.startSymbol, 'circle');
    expect(markLine.endSymbol, 'triangle');
    expect(markLine.startSymbolSize, 24);
    expect(markLine.endSymbolSize, 28);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(300, 240));
    final image = await recorder.endRecording().toImage(300, 240);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var endpointCyanPixels = 0;
    var bodyCyanPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (green > 180 && blue > 180 && red < 100) {
          if (y < 150 || y >= 157) {
            endpointCyanPixels += 1;
          } else {
            bodyCyanPixels += 1;
          }
        }
      }
    }

    expect(endpointCyanPixels, greaterThan(750));
    expect(endpointCyanPixels, greaterThan(bodyCyanPixels * 20));
  });

