  test('raw chart overlays honor mark line label border types', () async {
    Map<String, Object?> chart(String id, int left, String? borderType) {
      final label = <String, Object?>{
        'show': true,
        'formatter': 'Avg',
        'position': 'insideMiddleTop',
        'color': '#000000',
        'backgroundColor': '#ffff00',
        'borderColor': '#00ff00',
        'borderWidth': 3,
        'borderRadius': 3,
        'width': 64,
        'height': 24,
        'fontSize': 1,
      };
      if (borderType != null) {
        label['borderType'] = borderType;
      }
      return {
        'id': id,
        'left': left,
        'top': 20,
        'width': 100,
        'height': 76,
        'option': {
          'xAxis': {
            'data': ['Start', 'Middle', 'End'],
          },
          'series': [
            {
              'type': 'line',
              'data': [1, 5, 3],
              'lineStyle': {'color': '#000000', 'width': 1},
              'markLine': {
                'lineStyle': {'color': '#000000', 'width': 1},
                'label': label,
                'data': [
                  {'type': 'average'},
                ],
              },
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('solidMarkLineLabelBorder', 20, null),
              chart('dashedMarkLineLabelBorder', 140, 'dashed'),
              chart('dottedMarkLineLabelBorder', 260, 'dotted'),
            ],
          },
        ),
      ],
    );

    final markLines = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).map((overlay) => overlay.chartSeries.single.markLines.single).toList();
    expect(markLines[0].labelBorderType, isNull);
    expect(markLines[1].labelBorderType, 'dashed');
    expect(markLines[2].labelBorderType, 'dotted');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(420, 220));
    final image = await recorder.endRecording().toImage(420, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    int greenPixelsIn(int left, int right) {
      var pixels = 0;
      for (var y = 95; y < 150; y += 1) {
        for (var x = left; x < right; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (green > 180 && red < 100 && blue < 100) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final solidGreenPixels = greenPixelsIn(58, 138);
    final dashedGreenPixels = greenPixelsIn(178, 258);
    final dottedGreenPixels = greenPixelsIn(298, 378);

    expect(solidGreenPixels, greaterThan(70));
    expect(dashedGreenPixels, greaterThan(55));
    expect(dottedGreenPixels, greaterThan(30));
    expect(dashedGreenPixels, lessThan(solidGreenPixels));
    expect(dottedGreenPixels, lessThan(dashedGreenPixels * 0.7));
  });

