  test('raw chart overlays honor mark area border types', () async {
    Map<String, Object?> chart(String id, int left, String? borderType) {
      final itemStyle = <String, Object?>{
        'color': '#0000ff',
        'borderColor': '#00ff00',
        'borderWidth': 3,
      };
      if (borderType != null) {
        itemStyle['borderType'] = borderType;
      }
      return {
        'id': id,
        'left': left,
        'top': 20,
        'width': 100,
        'height': 76,
        'option': {
          'xAxis': {
            'data': ['Start', 'Middle', 'End'],
          },
          'series': [
            {
              'type': 'line',
              'data': [1, 5, 3],
              'lineStyle': {'color': '#000000', 'width': 1},
              'markArea': {
                'itemStyle': itemStyle,
                'data': [
                  [
                    {'xAxis': 'Start', 'yAxis': 1},
                    {'xAxis': 'End', 'yAxis': 5},
                  ],
                ],
              },
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('solidMarkAreaBorder', 20, null),
              chart('dashedMarkAreaBorder', 140, 'dashed'),
              chart('dottedMarkAreaBorder', 260, 'dotted'),
            ],
          },
        ),
      ],
    );

    final markAreas = fortuneRawShapeOverlays(
      workbook.activeSheet,
    ).map((overlay) => overlay.chartSeries.single.markAreas.single).toList();
    expect(markAreas[0].borderType, isNull);
    expect(markAreas[1].borderType, 'dashed');
    expect(markAreas[2].borderType, 'dotted');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(420, 220));
    final image = await recorder.endRecording().toImage(420, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    int greenPixelsIn(int left, int right) {
      var pixels = 0;
      for (var y = 95; y < 180; y += 1) {
        for (var x = left; x < right; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (green > 180 && red < 100 && blue < 100) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final solidGreenPixels = greenPixelsIn(50, 130);
    final dashedGreenPixels = greenPixelsIn(170, 250);
    final dottedGreenPixels = greenPixelsIn(290, 370);

    expect(solidGreenPixels, greaterThan(180));
    expect(dashedGreenPixels, greaterThan(100));
    expect(dottedGreenPixels, greaterThan(60));
    expect(dashedGreenPixels, lessThan(solidGreenPixels * 0.7));
    expect(dottedGreenPixels, lessThan(dashedGreenPixels * 0.7));
  });

