        final blue = bytes.getUint8(offset + 2);
        if (green > 180 && blue > 180 && red < 100) {
          if (x < 112) {
            leftCyanPixels += 1;
          } else if (x > 116) {
            rightCyanPixels += 1;
          }
        }
      }
    }
    expect(leftCyanPixels, greaterThan(80));
    expect(leftCyanPixels, greaterThan(rightCyanPixels));
  });

