  test(
    'raw chart overlays honor title numeric and percent positions',
    () async {
      Future<Offset> titleMinOffset(Object left, Object top) async {
        final workbook = FortuneWorkbook(
          sheets: [
            FortuneSheet(
              id: 's1',
              name: 'Sheet1',
              extraFields: {
                'chart': [
                  {
                    'id': 'chart1',
                    'left': 20,
                    'top': 20,
                    'width': 200,
                    'height': 120,
                    'option': {
                      'title': {
                        'text': 'Sales',
                        'left': left,
                        'top': top,
                        'textStyle': {'color': '#ff00ff', 'fontSize': 16},
                      },
                      'series': [
                        {
                          'type': 'line',
                          'data': [1, 4, 2, 5],
                        },
                      ],
                    },
                  },
                ],
              },
            ),
          ],
        );

        final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
        if (left is String && left.endsWith('%')) {
          expect(overlay.chartTitleLeftPercent, 0.60);
        } else {
          expect(overlay.chartTitleLeftOffset, 10);
        }
        if (top is String && top.endsWith('%')) {
          expect(overlay.chartTitleTopPercent, 0.50);
        } else {
          expect(overlay.chartTitleTopOffset, 10);
        }

        final recorder = ui.PictureRecorder();
        final canvas = Canvas(recorder);
        FortuneSheetPainter(
          workbook: workbook,
          selection: const FortuneSelection(row: 10, column: 10),
          scrollOffset: Offset.zero,
          sheetTabScrollOffset: 0,
          textDirection: TextDirection.ltr,
        ).paint(canvas, const Size(440, 320));
        final image = await recorder.endRecording().toImage(440, 320);
        final bytes = await image.toByteData(
          format: ui.ImageByteFormat.rawRgba,
        );

        expect(bytes, isNotNull);
        var minX = image.width;
        var minY = image.height;
        var pixels = 0;
        for (var y = 80; y < 230; y += 1) {
          for (var x = 20; x < 260; x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (red > 180 && blue > 180 && green < 120) {
              pixels += 1;
              minX = math.min(minX, x);
              minY = math.min(minY, y);
            }
          }
        }
        expect(pixels, greaterThan(10));
        return Offset(minX.toDouble(), minY.toDouble());
      }

      final numericOffset = await titleMinOffset(10, 10);
      final percentOffset = await titleMinOffset('60%', '50%');
      expect(percentOffset.dx, greaterThan(numericOffset.dx + 90));
      expect(percentOffset.dy, greaterThan(numericOffset.dy + 40));
    },
  );

