  test('raw chart overlays honor title border radius', () async {
    Future<int> cornerBorderPixels(double? radius) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 20,
                  'width': 150,
                  'height': 88,
                  'option': {
                    'title': {
                      'text': 'Sales',
                      'backgroundColor': '#fff4b8',
                      'borderColor': '#8b0000',
                      'borderWidth': 3,
                      'padding': [8, 14, 8, 14],
                      'borderRadius': ?radius,
                      'textStyle': {'color': '#111111', 'fontSize': 14},
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );

      final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
      expect(overlay.chartTitleBorderRadius, radius);

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(380, 270));
      final image = await recorder.endRecording().toImage(380, 270);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var minX = image.width;
      var minY = image.height;
      final borderPixels = <Offset>[];
      for (var y = 86; y < 140; y += 1) {
        for (var x = 40; x < 200; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 100 && red < 180 && green < 60 && blue < 60) {
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            borderPixels.add(Offset(x.toDouble(), y.toDouble()));
          }
        }
      }
      expect(borderPixels.length, greaterThan(80));
      return borderPixels
          .where((pixel) => pixel.dx < minX + 10 && pixel.dy < minY + 10)
          .length;
    }

    final squareCornerPixels = await cornerBorderPixels(null);
    final roundedCornerPixels = await cornerBorderPixels(14);
    expect(roundedCornerPixels, lessThan(squareCornerPixels - 10));
  });

