  test('raw chart overlays honor legend text font style', () async {
    Future<ui.Image> legendImage(String? fontStyle) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 20,
                  'width': 170,
                  'height': 100,
                  'option': {
                    'legend': {
                      'data': ['Actual', 'Plan'],
                      'textStyle': {
                        'color': '#ff00ff',
                        'fontSize': 14,
                        'fontStyle': ?fontStyle,
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                        'lineStyle': {'color': '#00ff00'},
                      },
                      {
                        'type': 'bar',
                        'data': [2, 3, 4, 1],
                        'itemStyle': {'color': '#00ffff'},
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );

      final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
      if (fontStyle == null) {
        expect(overlay.chartLegendTextFontStyle, isNull);
      } else {
        expect(overlay.chartLegendTextFontStyle, FontStyle.italic);
      }

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(400, 300));
      return recorder.endRecording().toImage(400, 300);
    }

    final normalImage = await legendImage(null);
    final italicImage = await legendImage('italic');
    final normalBytes = await normalImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    final italicBytes = await italicImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );

    expect(normalBytes, isNotNull);
    expect(italicBytes, isNotNull);
    var changedMagentaPixels = 0;
    for (var y = 158; y < 190; y += 1) {
      for (var x = 82; x < 235; x += 1) {
        final offset = ((y * normalImage.width) + x) * 4;
        final normalRed = normalBytes!.getUint8(offset);
        final normalGreen = normalBytes.getUint8(offset + 1);
        final normalBlue = normalBytes.getUint8(offset + 2);
        final italicRed = italicBytes!.getUint8(offset);
        final italicGreen = italicBytes.getUint8(offset + 1);
        final italicBlue = italicBytes.getUint8(offset + 2);
        final hasMagenta =
            (normalRed > 180 && normalBlue > 180 && normalGreen < 150) ||
            (italicRed > 180 && italicBlue > 180 && italicGreen < 150);
        final changed =
            (normalRed - italicRed).abs() +
            (normalGreen - italicGreen).abs() +
            (normalBlue - italicBlue).abs();
        if (hasMagenta && changed > 80) {
          changedMagentaPixels += 1;
        }
      }
    }
    expect(changedMagentaPixels, greaterThan(20));
  });

