  test('raw chart overlays honor legend string positions', () async {
    Future<Offset> firstOrangeSwatchTopLeft({bool positioned = false}) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
