                  'width': 190,
                  'height': 120,
                  'option': {
                    'legend': {
                      'data': ['A', 'B'],
                      if (positioned) 'left': 'center',
                      if (positioned) 'top': 'top',
                    },
                  },
                },
              ],
            },
          ),
        ],
      );

      final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
      if (positioned) {
        expect(overlay.chartLegendLeft, 'center');
        expect(overlay.chartLegendTop, 'top');
      } else {
        expect(overlay.chartLegendLeft, isNull);
        expect(overlay.chartLegendTop, isNull);
      }

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(400, 320));
      final image = await recorder.endRecording().toImage(400, 320);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var minX = image.width;
      var minY = image.height;
      var orangePixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 200 && green > 120 && blue < 80) {
            orangePixels += 1;
            minX = math.min(minX, x);
            minY = math.min(minY, y);
          }
        }
      }
      expect(orangePixels, greaterThan(20));
      return Offset(minX.toDouble(), minY.toDouble());
    }

    final defaultTopLeft = await firstOrangeSwatchTopLeft();
    final positionedTopLeft = await firstOrangeSwatchTopLeft(positioned: true);
    expect(positionedTopLeft.dx, greaterThan(defaultTopLeft.dx + 50));
    expect(positionedTopLeft.dy, lessThan(defaultTopLeft.dy - 40));
  });

