  test('raw chart overlays honor split area bands', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 150,
                'height': 130,
                'option': {
                  'xAxis': {
                    'splitArea': {
                      'show': true,
                      'areaStyle': {
                        'color': ['#ff00ff', '#ff00ff'],
                      },
                    },
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
              {
                'id': 'chart2',
                'left': 200,
                'top': 20,
                'width': 150,
                'height': 130,
                'option': {
                  'yAxis': {
                    'splitArea': {
                      'show': true,
                      'areaStyle': {
                        'color': ['#00ffff', '#00ffff'],
                      },
                    },
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays.first.chartVerticalSplitAreaVisible, isTrue);
    expect(
      overlays.first.chartVerticalSplitAreaColors.first,
      const Color(0xffff00ff),
    );
    expect(overlays.last.chartHorizontalSplitAreaVisible, isTrue);
    expect(
      overlays.last.chartHorizontalSplitAreaColors.first,
      const Color(0xff00ffff),
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(520, 320));
    final image = await recorder.endRecording().toImage(520, 320);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaBandPixels = 0;
    var cyanBandPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 120) {
          magentaBandPixels += 1;
        }
        if (green > 180 && blue > 180 && red < 120) {
          cyanBandPixels += 1;
        }
      }
    }
    expect(magentaBandPixels, greaterThan(1000));
    expect(cyanBandPixels, greaterThan(1000));
  });

