                        'show': true,
                        if (interval) 'interval': 1,
                        'areaStyle': {
                          'color': ['#00ffff', '#00ffff'],
                        },
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<(int, int)> countBandPixels(FortuneWorkbook workbook) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(520, 320));
      final image = await recorder.endRecording().toImage(520, 320);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var magentaBandPixels = 0;
      var cyanBandPixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 120) {
            magentaBandPixels += 1;
          }
          if (green > 180 && blue > 180 && red < 120) {
            cyanBandPixels += 1;
          }
        }
      }
      return (magentaBandPixels, cyanBandPixels);
    }

    final intervalWorkbook = workbookFor(interval: true);
    final overlays = fortuneRawShapeOverlays(intervalWorkbook.activeSheet);
    expect(overlays.first.chartVerticalSplitAreaInterval, 1);
    expect(overlays.last.chartHorizontalSplitAreaInterval, 1);

    final (allMagentaPixels, allCyanPixels) = await countBandPixels(
      workbookFor(interval: false),
    );
    final (intervalMagentaPixels, intervalCyanPixels) = await countBandPixels(
      intervalWorkbook,
    );

    expect(allMagentaPixels, greaterThan(1000));
    expect(allCyanPixels, greaterThan(1000));
    expect(intervalMagentaPixels, lessThan(allMagentaPixels * 0.7));
    expect(intervalCyanPixels, lessThan(allCyanPixels * 0.7));
    expect(intervalMagentaPixels, greaterThan(500));
    expect(intervalCyanPixels, greaterThan(500));
  });

