  test('raw chart overlays honor split line types', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 150,
                'height': 100,
                'option': {
                  'xAxis': {
                    'splitLine': {
                      'show': true,
                      'lineStyle': {
                        'color': '#ff0000',
                        'width': 4,
                        'type': 'dashed',
                      },
                    },
                  },
                  'yAxis': {
                    'splitLine': {
                      'show': true,
                      'lineStyle': {
                        'color': '#ff0000',
                        'width': 5,
                        'type': 'dotted',
                      },
                    },
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartVerticalGridLineType, 'dashed');
    expect(overlay.chartHorizontalGridLineType, 'dotted');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(400, 300));
    final image = await recorder.endRecording().toImage(400, 300);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var redGridPixels = 0;
    var maxRedRowRuns = 0;
    var maxRedColumnRuns = 0;
    for (var y = 0; y < image.height; y += 1) {
      var rowRuns = 0;
      var inRedRun = false;
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isRed = red > 180 && green < 80 && blue < 80;
        if (isRed) {
          redGridPixels += 1;
          if (!inRedRun) {
            rowRuns += 1;
          }
        }
        inRedRun = isRed;
      }
      maxRedRowRuns = math.max(maxRedRowRuns, rowRuns);
    }
    for (var x = 0; x < image.width; x += 1) {
      var columnRuns = 0;
      var inRedRun = false;
      for (var y = 0; y < image.height; y += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isRed = red > 180 && green < 80 && blue < 80;
        if (isRed && !inRedRun) {
          columnRuns += 1;
        }
        inRedRun = isRed;
      }
      maxRedColumnRuns = math.max(maxRedColumnRuns, columnRuns);
    }
    expect(redGridPixels, greaterThan(250));
    expect(maxRedRowRuns, greaterThan(3));
    expect(maxRedColumnRuns, greaterThan(3));
  });

