                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays.first.chartHorizontalMinorGridLineDashOffset, isNull);
    expect(overlays.last.chartHorizontalMinorGridLineDashOffset, 7);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(420, 260));
    final image = await recorder.endRecording().toImage(420, 260);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaLocalMinX = image.width;
    var cyanLocalMinX = image.width;
    var magentaPixels = 0;
    var cyanPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaPixels += 1;
          magentaLocalMinX = math.min(magentaLocalMinX, x - 20);
        }
        if (green > 180 && blue > 180 && red < 100) {
          cyanPixels += 1;
          cyanLocalMinX = math.min(cyanLocalMinX, x - 170);
        }
      }
    }
    expect(magentaPixels, greaterThan(100));
    expect(cyanPixels, greaterThan(70));
    expect(cyanLocalMinX, greaterThan(magentaLocalMinX + 3));
  });

