          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green > 180 && blue < 100) {
            yellowPixels += 1;
            yellowLocalMinY = math.min(yellowLocalMinY, y - 20);
          }
          if (green > 180 && blue > 180 && red < 100) {
            cyanPixels += 1;
            cyanLocalMinY = math.min(cyanLocalMinY, y - 20);
          }
        }
      }

      expect(yellowPixels, greaterThan(100));
      expect(cyanPixels, greaterThan(70));
      expect(cyanLocalMinY, greaterThan(yellowLocalMinY + 3));
    },
  );

