            'minorSplitLine': showXAxis
                ? {
                    'show': true,
                    'lineStyle': {'color': color, 'width': 6, 'opacity': 0.25},
                  }
                : {'show': false},
          },
          'yAxis': {
            'axisLine': {'show': false},
            'axisLabel': {'show': false},
            'minorTick': {'splitNumber': 4},
            'minorSplitLine': showXAxis
                ? {'show': false}
                : {
                    'show': true,
                    'lineStyle': {'color': color, 'width': 6, 'opacity': 0.25},
                  },
          },
          'series': [
            {
              'type': 'line',
              'data': [1, 4, 2, 5],
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('xMinorOpacity', 40, '#ff00ff', 'x'),
              chart('yMinorOpacity', 240, '#00ffff', 'y'),
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays.first.chartVerticalMinorGridLineOpacity, 0.25);
    expect(overlays.last.chartHorizontalMinorGridLineOpacity, 0.25);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    for (final overlay in overlays) {
      fortuneDrawRawShapeOverlay(
        canvas,
        overlay.rect,
        overlay,
        const Rect.fromLTWH(0, 0, 430, 180),
      );
    }
    final image = await recorder.endRecording().toImage(430, 180);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var fadedMagentaPixels = 0;
    var fadedCyanPixels = 0;
    var strongMagentaPixels = 0;
    var strongCyanPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green >= 120 && green < 245) {
          fadedMagentaPixels += 1;
        }
        if (green > 180 && blue > 180 && red >= 120 && red < 245) {
          fadedCyanPixels += 1;
        }
        if (red > 180 && blue > 180 && green < 120) {
          strongMagentaPixels += 1;
        }
        if (green > 180 && blue > 180 && red < 120) {
          strongCyanPixels += 1;
        }
      }
    }

    expect(fadedMagentaPixels, greaterThan(700));
    expect(fadedCyanPixels, greaterThan(700));
    expect(strongMagentaPixels, lessThan(120));
    expect(strongCyanPixels, lessThan(120));
  });

