  test('raw chart overlays honor axis line symbol offsets', () async {
    FortuneWorkbook workbookFor({required double offsetX}) {
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                {
                  'id': 'axisLineSymbolOffset$offsetX',
                  'left': 20,
                  'top': 20,
                  'width': 150,
                  'height': 100,
                  'option': {
                    'xAxis': {
                      'axisLabel': {'show': false},
                      'axisLine': {
                        'show': true,
                        'symbol': ['none', 'arrow'],
                        'symbolSize': [24, 24],
                        'symbolOffset': [offsetX, 0],
                        'lineStyle': {'color': '#ff0000', 'width': 4},
                      },
                    },
                    'yAxis': {
                      'axisLabel': {'show': false},
                      'axisLine': {'show': false},
                    },
                    'series': [
                      {
                        'type': 'line',
                        'lineStyle': {'color': '#0000ff'},
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<({int pixels, int minX, int maxX})> redBounds(
      FortuneWorkbook workbook,
    ) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(420, 280));
      final image = await recorder.endRecording().toImage(420, 280);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var pixels = 0;
      var minX = image.width;
      var maxX = -1;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final byteOffset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(byteOffset);
          final green = bytes.getUint8(byteOffset + 1);
          final blue = bytes.getUint8(byteOffset + 2);
          if (red > 180 && green < 100 && blue < 100) {
            pixels += 1;
            minX = math.min(minX, x);
            maxX = math.max(maxX, x);
          }
        }
      }
      return (pixels: pixels, minX: minX, maxX: maxX);
    }

    final offsetWorkbook = workbookFor(offsetX: 24);
    final overlay = fortuneRawShapeOverlays(offsetWorkbook.activeSheet).single;
    expect(overlay.chartXAxisLineSymbolOffset, const Offset(24, 0));

    final defaultBounds = await redBounds(workbookFor(offsetX: 0));
    final offsetBounds = await redBounds(offsetWorkbook);

    expect(defaultBounds.pixels, greaterThan(180));
    expect(offsetBounds.pixels, greaterThan(180));
    expect(offsetBounds.minX, defaultBounds.minX);
    expect(offsetBounds.maxX, greaterThan(defaultBounds.maxX + 15));
  });

