      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(400, 280));
    final image = await recorder.endRecording().toImage(400, 280);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPointerPixels = 0;
    var cyanPointerPixels = 0;
    var greenShadowPixels = 0;
    var orangeShadowPixels = 0;
    var blueHandlePixels = 0;
    var yellowLabelPixels = 0;
    var navyLabelBorderPixels = 0;
    var darkLabelTextPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 120) {
          magentaPointerPixels += 1;
        }
        if (green > 180 && blue > 180 && red < 120) {
          cyanPointerPixels += 1;
        }
        if (green > 170 && red < 120 && blue < 120) {
          greenShadowPixels += 1;
        }
        if (red > 170 && green > 90 && green < 180 && blue < 120) {
          orangeShadowPixels += 1;
        }
        if (red > 30 && red < 100 && green > 70 && green < 150 && blue > 120) {
          blueHandlePixels += 1;
        }
        if (red > 230 && green > 210 && blue > 120 && blue < 200) {
          yellowLabelPixels += 1;
        }
        if (red > 10 &&
            red < 45 &&
            green > 35 &&
            green < 75 &&
            blue > 70 &&
            blue < 110) {
          navyLabelBorderPixels += 1;
        }
        if (red < 45 && green > 20 && green < 65 && blue > 30 && blue < 80) {
          darkLabelTextPixels += 1;
        }
      }
    }
    expect(magentaPointerPixels, greaterThan(80));
    expect(cyanPointerPixels, greaterThan(80));
    expect(greenShadowPixels, greaterThan(40));
    expect(orangeShadowPixels, greaterThan(40));
    expect(blueHandlePixels, greaterThan(80));
    expect(blueHandlePixels, lessThan(260));
    expect(yellowLabelPixels, greaterThan(250));
    expect(navyLabelBorderPixels, greaterThan(20));
    expect(darkLabelTextPixels, greaterThan(10));
  });

