  test('raw chart overlays honor axis pointer line dash offsets', () async {
    Map<String, Object?> chart(
      String id,
      double left,
      String color,
      double dashOffset,
    ) {
      return {
        'id': id,
        'left': left,
        'top': 20,
        'width': 180,
        'height': 120,
        'option': {
          'xAxis': {
            'data': ['Jan', 'Feb', 'Mar', 'Apr'],
            'axisLabel': {'show': false},
          },
          'yAxis': {
            'axisPointer': {
              'show': true,
              'value': 3,
              'lineStyle': {
                'color': color,
                'width': 4,
                'type': 'dashed',
                'dashOffset': dashOffset,
              },
              'label': {'show': false},
              'handle': {'show': false},
            },
            'axisLabel': {'show': false},
          },
          'series': [
            {
              'type': 'line',
              'lineStyle': {'color': '#000000'},
              'itemStyle': {'color': '#000000'},
              'data': [1, 2, 3, 4],
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('axisPointerDashOffsetBase', 80, '#ffff00', 0),
              chart('axisPointerDashOffsetShifted', 320, '#00ffff', 8),
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays[0].chartYAxisPointerDashOffset, 0);
    expect(overlays[1].chartYAxisPointerDashOffset, 8);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    for (final overlay in overlays) {
      fortuneDrawRawShapeOverlay(
        canvas,
        overlay.rect,
        overlay,
        const Rect.fromLTWH(0, 0, 540, 190),
      );
    }
    final image = await recorder.endRecording().toImage(540, 190);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    Rect boundsFor(bool Function(int red, int green, int blue) matches) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      var pixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            pixels += 1;
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
          }
        }
      }
      expect(pixels, greaterThan(250));
      expect(maxX, greaterThan(minX));
      expect(maxY, greaterThan(minY));
      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    final baseBounds = boundsFor(
      (red, green, blue) => red > 220 && green > 220 && blue < 100,
    );
    final shiftedBounds = boundsFor(
      (red, green, blue) => green > 220 && blue > 220 && red < 100,
    );

    final baseRelativeLeft = baseBounds.left - overlays[0].rect.left;
    final shiftedRelativeLeft = shiftedBounds.left - overlays[1].rect.left;

    expect(shiftedRelativeLeft, greaterThan(baseRelativeLeft + 2));
    expect(shiftedBounds.width, closeTo(baseBounds.width, 4));
  });

