  test(
    'raw chart overlays distinguish axis pointer dashed and dotted lines',
    () async {
      Map<String, Object?> chart(
        String id,
        double left,
        String color,
        String type,
      ) {
        return {
          'id': id,
          'left': left,
          'top': 20,
          'width': 180,
          'height': 120,
          'option': {
            'xAxis': {
              'data': ['Jan', 'Feb', 'Mar', 'Apr'],
              'axisLabel': {'show': false},
            },
            'yAxis': {
              'axisPointer': {
                'show': true,
                'value': 3,
                'lineStyle': {'color': color, 'width': 6, 'type': type},
                'label': {'show': false},
                'handle': {'show': false},
              },
              'axisLabel': {'show': false},
            },
            'series': [
              {
                'type': 'line',
                'lineStyle': {'color': '#000000'},
                'itemStyle': {'color': '#000000'},
                'data': [1, 2, 3, 4],
              },
            ],
          },
        };
      }

      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                chart('axisPointerDashedLine', 80, '#ffff00', 'dashed'),
                chart('axisPointerDottedLine', 320, '#00ffff', 'dotted'),
              ],
            },
          ),
        ],
      );

      final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
      expect(overlays[0].chartYAxisPointerType, 'dashed');
      expect(overlays[1].chartYAxisPointerType, 'dotted');

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      for (final overlay in overlays) {
        fortuneDrawRawShapeOverlay(
          canvas,
          overlay.rect,
          overlay,
          const Rect.fromLTWH(0, 0, 540, 190),
        );
      }
      final image = await recorder.endRecording().toImage(540, 190);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      int pixelsFor(bool Function(int red, int green, int blue) matches) {
        var pixels = 0;
        for (var y = 0; y < image.height; y += 1) {
          for (var x = 0; x < image.width; x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (matches(red, green, blue)) {
              pixels += 1;
            }
          }
        }
        return pixels;
      }

      final dashedPixels = pixelsFor(
        (red, green, blue) => red > 220 && green > 220 && blue < 100,
      );
      final dottedPixels = pixelsFor(
        (red, green, blue) => green > 220 && blue > 220 && red < 100,
      );

      expect(dashedPixels, greaterThan(250));
      expect(dottedPixels, greaterThan(120));
      expect(dottedPixels, lessThan(dashedPixels * 0.75));
    },
  );

