  test('raw chart overlays honor axis pointer line shadows', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'axisPointerLineShadow',
                'left': 80,
                'top': 20,
                'width': 180,
                'height': 120,
                'option': {
                  'xAxis': {
                    'data': ['Jan', 'Feb', 'Mar', 'Apr'],
                    'axisLabel': {'show': false},
                  },
                  'yAxis': {
                    'axisPointer': {
                      'show': true,
                      'value': 3,
                      'lineStyle': {
                        'color': '#ffff00',
                        'width': 4,
                        'shadowColor': '#00ff00',
                        'shadowBlur': 0,
                        'shadowOffsetX': 0,
                        'shadowOffsetY': 18,
                      },
                      'label': {'show': false},
                      'handle': {'show': false},
                    },
                    'axisLabel': {'show': false},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'lineStyle': {'color': '#000000'},
                      'itemStyle': {'color': '#000000'},
                      'data': [1, 2, 3, 4],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartYAxisPointerShadowColor, const Color(0xff00ff00));
    expect(overlay.chartYAxisPointerShadowBlur, 0);
    expect(overlay.chartYAxisPointerShadowOffsetX, 0);
    expect(overlay.chartYAxisPointerShadowOffsetY, 18);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      overlay.rect,
      overlay,
      const Rect.fromLTWH(0, 0, 320, 190),
    );
    final image = await recorder.endRecording().toImage(320, 190);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    Rect boundsFor(bool Function(int red, int green, int blue) matches) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      var pixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            pixels += 1;
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
          }
        }
      }
      expect(pixels, greaterThan(350));
      expect(maxX, greaterThan(minX));
      expect(maxY, greaterThan(minY));
      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    final lineBounds = boundsFor(
      (red, green, blue) => red > 220 && green > 220 && blue < 100,
    );
    final shadowBounds = boundsFor(
      (red, green, blue) => green > 220 && red < 90 && blue < 90,
    );

    expect(shadowBounds.top, greaterThan(lineBounds.top + 14));
    expect(shadowBounds.width, closeTo(lineBounds.width, 4));
  });

