  test('raw chart axis pointer value positions rendered line', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 180,
                'height': 120,
                'option': {
                  'xAxis': {
                    'data': ['Jan', 'Feb', 'Mar', 'Apr'],
                    'axisPointer': {
                      'show': true,
                      'value': 'Apr',
                      'lineStyle': {'color': '#ff00ff', 'width': 4},
                    },
                    'axisLabel': {'show': false},
                  },
                  'yAxis': {
                    'axisLabel': {'show': false},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 2, 3, 4],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(320, 220));
    final image = await recorder.endRecording().toImage(320, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var rightBandMagentaPixels = 0;
    var centerBandMagentaPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 120) {
          if (x >= 145) {
            rightBandMagentaPixels += 1;
          }
          if (x >= 85 && x <= 125) {
            centerBandMagentaPixels += 1;
          }
        }
      }
    }
    expect(rightBandMagentaPixels, greaterThan(40));
    expect(centerBandMagentaPixels, lessThan(30));
  });

