      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    Rect textBoundsInside(Rect labelBounds) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      for (
        var y = labelBounds.top.floor();
        y <= labelBounds.bottom.ceil();
        y += 1
      ) {
        for (
          var x = labelBounds.left.floor();
          x <= labelBounds.right.ceil();
          x += 1
        ) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red < 60 && green < 60 && blue < 60) {
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
          }
        }
      }
      expect(maxX, greaterThan(minX));
      expect(maxY, greaterThan(minY));
      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    final defaultLabelBounds = boundsFor(
      (red, green, blue) => red > 220 && green > 220 && blue < 100,
    );
    final alignedLabelBounds = boundsFor(
      (red, green, blue) => green > 220 && blue > 220 && red < 100,
    );
    final defaultTextBounds = textBoundsInside(defaultLabelBounds);
    final alignedTextBounds = textBoundsInside(alignedLabelBounds);

    expect(
      alignedTextBounds.left - alignedLabelBounds.left,
      greaterThan(defaultTextBounds.left - defaultLabelBounds.left + 35),
    );
    expect(
      alignedTextBounds.top - alignedLabelBounds.top,
      greaterThan(defaultTextBounds.top - defaultLabelBounds.top + 12),
    );
  });

