          },
          'yAxis': {
            'axisPointer': {
              'show': true,
              'value': 3,
              'lineStyle': {'color': '#ff0000', 'width': 2},
              'label': {'show': false},
              'handle': {
                'show': true,
                'icon': 'rect',
                'size': [20, 20],
                'color': color,
                'margin': margin,
              },
            },
            'axisLabel': {'show': false},
          },
          'series': [
            {
              'type': 'line',
              'lineStyle': {'color': '#000000'},
              'itemStyle': {'color': '#000000'},
              'data': [1, 2, 3, 4],
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('axisPointerHandleSmallMargin', 80, '#ffff00', 4),
              chart('axisPointerHandleLargeMargin', 320, '#00ffff', 36),
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays[0].chartYAxisPointerHandleMargin, 4);
    expect(overlays[1].chartYAxisPointerHandleMargin, 36);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    for (final overlay in overlays) {
      fortuneDrawRawShapeOverlay(
        canvas,
        overlay.rect,
        overlay,
        const Rect.fromLTWH(0, 0, 540, 190),
      );
    }
    final image = await recorder.endRecording().toImage(540, 190);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    Rect boundsFor(bool Function(int red, int green, int blue) matches) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
          }
        }
      }
      expect(maxX, greaterThan(minX));
      expect(maxY, greaterThan(minY));
      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    final smallMarginBounds = boundsFor(
      (red, green, blue) => red > 220 && green > 220 && blue < 100,
    );
    final largeMarginBounds = boundsFor(
      (red, green, blue) => green > 220 && blue > 220 && red < 100,
    );

    expect(smallMarginBounds.width, greaterThan(17));
    expect(largeMarginBounds.width, greaterThan(17));
    expect(smallMarginBounds.height, greaterThan(17));
    expect(largeMarginBounds.height, greaterThan(17));

    final smallRelativeLeft = smallMarginBounds.left - overlays[0].rect.left;
    final largeRelativeLeft = largeMarginBounds.left - overlays[1].rect.left;
    expect(largeRelativeLeft, lessThan(smallRelativeLeft - 24));
  });

