  test('raw chart overlays honor axis pointer handle path icons', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 180,
                'height': 120,
                'option': {
                  'xAxis': {
                    'data': ['Jan', 'Feb', 'Mar', 'Apr'],
                    'axisLabel': {'show': false},
                  },
                  'yAxis': {
                    'axisPointer': {
                      'show': true,
                      'value': 3,
                      'lineStyle': {'color': '#ff0000', 'width': 3},
                      'handle': {
                        'show': true,
                        'icon': 'path://M0,0L24,0L12,24Z',
                        'size': [28, 28],
                        'color': '#00ff00',
                        'margin': 4,
                      },
                    },
                    'axisLabel': {'show': false},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'lineStyle': {'color': '#000000'},
                      'itemStyle': {'color': '#000000'},
                      'data': [1, 2, 3, 4],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartYAxisPointerHandleIcon, 'path://M0,0L24,0L12,24Z');
    expect(overlay.chartYAxisPointerHandleSize, [28, 28]);
    expect(overlay.chartYAxisPointerHandleColor, const Color(0xff00ff00));

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      const Rect.fromLTWH(20, 20, 180, 120),
      overlay,
      const Rect.fromLTWH(0, 0, 260, 190),
    );
    final image = await recorder.endRecording().toImage(260, 190);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var minGreenX = image.width;
    var minGreenY = image.height;
    var maxGreenX = -1;
    var maxGreenY = -1;
    var greenHandlePixels = 0;
    var redPointerPixels = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (green > 180 && red < 90 && blue < 90) {
          greenHandlePixels += 1;
          minGreenX = math.min(minGreenX, x);
          minGreenY = math.min(minGreenY, y);
          maxGreenX = math.max(maxGreenX, x);
          maxGreenY = math.max(maxGreenY, y);
        }
        if (red > 180 && green < 100 && blue < 100) {
          redPointerPixels += 1;
        }
      }
    }

    expect(redPointerPixels, greaterThan(80));
    expect(greenHandlePixels, greaterThan(150));
    expect(greenHandlePixels, lessThan(720));
    expect(maxGreenX - minGreenX, greaterThan(20));
    expect(maxGreenY - minGreenY, greaterThan(20));

    var lowerCornerGreenPixels = 0;
    for (var y = maxGreenY - 5; y <= maxGreenY; y += 1) {
      for (var x = minGreenX; x <= maxGreenX; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final nearLeftCorner = x < minGreenX + 6;
        final nearRightCorner = x > maxGreenX - 6;
        if ((nearLeftCorner || nearRightCorner) &&
            green > 180 &&
            red < 90 &&
            blue < 90) {
          lowerCornerGreenPixels += 1;
        }
      }
    }

    expect(lowerCornerGreenPixels, lessThan(12));
  });

