  test(
    'raw chart overlays render axis pointer handle rectangle aliases',
    () async {
      Map<String, Object?> chart(
        String id,
        double left,
        String color, {
        required bool xAxis,
      }) {
        return {
          'id': id,
          'left': left,
          'top': 20,
          'width': 180,
          'height': 120,
          'option': {
            'xAxis': {
              'data': ['Jan', 'Feb', 'Mar', 'Apr'],
              if (xAxis)
                'axisPointer': {
                  'show': true,
                  'value': 'Feb',
                  'lineStyle': {'color': '#ff0000', 'width': 3},
                  'handle': {
                    'show': true,
                    'icon': 'rectangle',
                    'size': [28, 28],
                    'color': color,
                    'margin': 4,
                  },
                },
              'axisLabel': {'show': false},
            },
            'yAxis': {
              if (!xAxis)
                'axisPointer': {
                  'show': true,
                  'value': 3,
                  'lineStyle': {'color': '#ff0000', 'width': 3},
                  'handle': {
                    'show': true,
                    'icon': 'rectangle',
                    'size': [28, 28],
                    'color': color,
                    'margin': 4,
                  },
                },
              'axisLabel': {'show': false},
            },
            'series': [
              {
                'type': 'line',
                'lineStyle': {'color': '#000000'},
                'itemStyle': {'color': '#000000'},
                'data': [1, 2, 3, 4],
              },
            ],
          },
        };
      }

      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                chart('yAxisRectangleHandle', 80, '#ffff00', xAxis: false),
                chart('xAxisRectangleHandle', 320, '#00ffff', xAxis: true),
              ],
            },
          ),
        ],
      );

      final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
      expect(overlays[0].chartYAxisPointerHandleVisible, isTrue);
      expect(overlays[0].chartYAxisPointerHandleIcon, 'rectangle');
      expect(overlays[0].chartYAxisPointerHandleSize, [28, 28]);
      expect(overlays[1].chartXAxisPointerHandleVisible, isTrue);
      expect(overlays[1].chartXAxisPointerHandleIcon, 'rectangle');
      expect(overlays[1].chartXAxisPointerHandleSize, [28, 28]);

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      for (final overlay in overlays) {
        fortuneDrawRawShapeOverlay(
          canvas,
          overlay.rect,
          overlay,
          const Rect.fromLTWH(0, 0, 540, 220),
        );
      }
      final image = await recorder.endRecording().toImage(540, 220);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      Rect boundsFor(bool Function(int red, int green, int blue) matches) {
        var minX = image.width;
        var minY = image.height;
        var maxX = -1;
        var maxY = -1;
        var pixels = 0;
        for (var y = 0; y < image.height; y += 1) {
          for (var x = 0; x < image.width; x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (matches(red, green, blue)) {
              pixels += 1;
              minX = math.min(minX, x);
              minY = math.min(minY, y);
              maxX = math.max(maxX, x);
              maxY = math.max(maxY, y);
            }
          }
        }
        expect(pixels, greaterThan(650));
        expect(pixels, lessThan(900));
        expect(maxX - minX, greaterThan(24));
        expect(maxY - minY, greaterThan(24));
        return Rect.fromLTRB(
          minX.toDouble(),
          minY.toDouble(),
          maxX.toDouble(),
          maxY.toDouble(),
        );
      }

      int cornerPixels(
        Rect bounds,
        bool Function(int red, int green, int blue) matches,
      ) {
        var pixels = 0;
        for (var x = bounds.left.toInt(); x <= bounds.right.toInt(); x += 1) {
          final nearLeftCorner = x < bounds.left + 4;
          final nearRightCorner = x > bounds.right - 4;
          if (!nearLeftCorner && !nearRightCorner) {
            continue;
          }
          for (var y = bounds.top.toInt(); y <= bounds.bottom.toInt(); y += 1) {
            final nearTopCorner = y < bounds.top + 4;
            final nearBottomCorner = y > bounds.bottom - 4;
            if (!nearTopCorner && !nearBottomCorner) {
              continue;
            }
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (matches(red, green, blue)) {
              pixels += 1;
            }
          }
        }
        return pixels;
      }

      bool yellow(int red, int green, int blue) =>
          red > 220 && green > 220 && blue < 100;
      bool cyan(int red, int green, int blue) =>
          green > 220 && blue > 220 && red < 100;

      final yAxisBounds = boundsFor(yellow);
      final xAxisBounds = boundsFor(cyan);

      expect(cornerPixels(yAxisBounds, yellow), greaterThan(55));
      expect(cornerPixels(xAxisBounds, cyan), greaterThan(55));
    },
  );

