      var greenHandlePixels = 0;
      var redPointerPixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (green > 180 && red < 90 && blue < 90) {
            greenHandlePixels += 1;
            minGreenX = math.min(minGreenX, x);
            minGreenY = math.min(minGreenY, y);
            maxGreenX = math.max(maxGreenX, x);
            maxGreenY = math.max(maxGreenY, y);
          }
          if (red > 180 && green < 100 && blue < 100) {
            redPointerPixels += 1;
          }
        }
      }

      expect(redPointerPixels, greaterThan(80));
      expect(greenHandlePixels, greaterThan(620));
      expect(greenHandlePixels, lessThan(850));
      expect(maxGreenX - minGreenX, greaterThan(24));
      expect(maxGreenY - minGreenY, greaterThan(24));

      var cornerGreenPixels = 0;
      for (var x = minGreenX; x <= maxGreenX; x += 1) {
        final nearLeftCorner = x < minGreenX + 4;
        final nearRightCorner = x > maxGreenX - 4;
        if (!nearLeftCorner && !nearRightCorner) {
          continue;
        }
        for (var y = minGreenY; y <= maxGreenY; y += 1) {
          final nearTopCorner = y < minGreenY + 4;
          final nearBottomCorner = y > maxGreenY - 4;
          if (!nearTopCorner && !nearBottomCorner) {
            continue;
          }
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (green > 180 && red < 90 && blue < 90) {
            cornerGreenPixels += 1;
          }
        }
      }

      expect(cornerGreenPixels, lessThan(60));
    },
  );

