                      'width': 88,
                      'height': 36,
                    },
                  },
                  'xAxis': {
                    'data': ['Jan', 'Feb', 'Mar'],
                  },
                  'yAxis': {},
                  'series': [
                    {
                      'name': 'Sales',
                      'type': 'line',
                      'data': [1, 4, 7],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartTooltipBorderRadius, 18);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      const Rect.fromLTWH(20, 20, 170, 110),
      overlay,
      const Rect.fromLTWH(0, 0, 260, 180),
    );
    final image = await recorder.endRecording().toImage(260, 180);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var minX = image.width;
    var minY = image.height;
    var maxX = -1;
    var maxY = -1;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 210 && blue > 210 && green < 80) {
          minX = math.min(minX, x);
          minY = math.min(minY, y);
          maxX = math.max(maxX, x);
          maxY = math.max(maxY, y);
        }
      }
    }

    expect(maxX, greaterThan(minX));
    expect(maxY, greaterThan(minY));
    var centerMagentaPixels = 0;
    var cornerMagentaPixels = 0;
    for (var y = minY; y <= maxY; y += 1) {
      for (var x = minX; x <= maxX; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 210 && blue > 210 && green < 80) {
          final inLeftCorner = x < minX + 10;
          final inRightCorner = x > maxX - 10;
          final inTopCorner = y < minY + 10;
          final inBottomCorner = y > maxY - 10;
          if ((inLeftCorner || inRightCorner) &&
              (inTopCorner || inBottomCorner)) {
            cornerMagentaPixels += 1;
          }
          if (x >= minX + 22 && x <= maxX - 22 && y >= minY + 8) {
            centerMagentaPixels += 1;
          }
        }
      }
    }

    expect(centerMagentaPixels, greaterThan(600));
    expect(cornerMagentaPixels, lessThan(220));
  });

