          blackTextPixels += 1;
          minBlackX = math.min(minBlackX, x);
          maxBlackX = math.max(maxBlackX, x);
        }
        if (green > 160 && red < 120 && blue < 120) {
          greenShadowPixels += 1;
          minGreenX = math.min(minGreenX, x);
          maxGreenX = math.max(maxGreenX, x);
        }
      }
    }

