                    'data': ['Jan', 'Feb', 'Mar'],
                  },
                  'yAxis': {},
                  'series': [
                    {
                      'name': 'S',
                      'type': 'line',
                      'data': [1, 1, 1],
                    },
                    {
                      'name': 'LongLongLong',
                      'type': 'line',
                      'data': [9, 9, 9],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartTooltipOrder, 'valueDesc');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      const Rect.fromLTWH(20, 20, 190, 130),
      overlay,
      const Rect.fromLTWH(0, 0, 280, 210),
      hoverPosition: const Offset(112, 82),
    );
    final image = await recorder.endRecording().toImage(280, 210);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var minTooltipY = image.height;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 210 && blue > 210 && green < 80) {
          minTooltipY = math.min(minTooltipY, y);
        }
      }
    }

    var firstRowWhitePixels = 0;
    var secondRowWhitePixels = 0;
    for (var y = minTooltipY + 4; y < minTooltipY + 36; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 210 && green > 210 && blue > 210) {
          if (y < minTooltipY + 20) {
            firstRowWhitePixels += 1;
          } else {
            secondRowWhitePixels += 1;
          }
        }
      }
    }
    expect(firstRowWhitePixels, greaterThan(secondRowWhitePixels * 2));
  });

