                'left': 20,
                'top': 20,
                'width': 150,
                'height': 110,
                'option': {
                  'tooltip': {
                    'axisPointer': {
                      'type': 'shadow',
                      'shadowStyle': {
                        'color': '#0000ff',
                        'shadowColor': '#ff0000',
                        'shadowBlur': 0,
                        'shadowOffsetX': 18,
                        'shadowOffsetY': 0,
                      },
                    },
                  },
                  'xAxis': {
                    'data': ['A', 'B', 'C'],
                    'axisLabel': {'show': false},
                  },
                  'yAxis': {
                    'axisLabel': {'show': false},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartXAxisPointerAreaVisible, isTrue);
    expect(overlay.chartXAxisPointerAreaColor, const Color(0xff0000ff));
    expect(overlay.chartXAxisPointerAreaShadowColor, const Color(0xffff0000));
    expect(overlay.chartXAxisPointerAreaShadowBlur, 0);
    expect(overlay.chartXAxisPointerAreaShadowOffsetX, 18);
    expect(overlay.chartXAxisPointerAreaShadowOffsetY, 0);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    fortuneDrawRawShapeOverlay(
      canvas,
      overlay.rect,
      overlay,
      const Rect.fromLTWH(0, 0, 240, 170),
    );
    final image = await recorder.endRecording().toImage(240, 170);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    Rect boundsFor(bool Function(int red, int green, int blue) matches) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      var pixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            pixels += 1;
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
          }
        }
      }
      expect(pixels, greaterThan(250));
      expect(maxX, greaterThan(minX));
      expect(maxY, greaterThan(minY));
      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    final areaBounds = boundsFor(
      (red, green, blue) => blue > 180 && red < 100 && green < 100,
    );
    final shadowBounds = boundsFor(
      (red, green, blue) => red > 180 && green < 100 && blue < 100,
    );

    expect(shadowBounds.left, greaterThan(areaBounds.left + 10));
    expect(shadowBounds.right, greaterThan(areaBounds.right + 10));
    expect(shadowBounds.height, closeTo(areaBounds.height, 4));
  });

