                      'axisLabel': {'show': false},
                    },
                    'yAxis': {
                      'axisLabel': {'show': false},
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );

      final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
      expect(overlay.chartXAxisPointerAreaVisible, isTrue);
      expect(overlay.chartXAxisPointerAreaColor, isNull);

      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(400, 280));
      final image = await recorder.endRecording().toImage(400, 280);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

      expect(bytes, isNotNull);
      var defaultBandPixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          final alpha = bytes.getUint8(offset + 3);
          final rawDefaultShadow =
              red >= 145 &&
              red <= 155 &&
              green >= 145 &&
              green <= 155 &&
              blue >= 145 &&
              blue <= 155 &&
              alpha >= 70 &&
              alpha <= 85;
          final compositedDefaultShadow =
              red >= 220 &&
              red <= 225 &&
              green >= 220 &&
              green <= 225 &&
              blue >= 220 &&
              blue <= 225 &&
              alpha >= 250;
          if (rawDefaultShadow || compositedDefaultShadow) {
            defaultBandPixels += 1;
          }
        }
      }
      expect(defaultBandPixels, greaterThan(700));
    },
  );

