            maxY = math.max(maxY, y);
          }
        }
      }
      expect(pixels, greaterThan(250));
      expect(maxX, greaterThan(minX));
      expect(maxY, greaterThan(minY));
      return Rect.fromLTRB(
        minX.toDouble(),
        minY.toDouble(),
        maxX.toDouble(),
        maxY.toDouble(),
      );
    }

    final areaBounds = boundsFor(
      (red, green, blue) => blue > 180 && red < 100 && green < 100,
    );
    final shadowBounds = boundsFor(
      (red, green, blue) => red > 180 && green < 100 && blue < 100,
    );

    expect(shadowBounds.top, greaterThan(areaBounds.top + 10));
    expect(shadowBounds.bottom, greaterThan(areaBounds.bottom + 10));
    expect(shadowBounds.width, closeTo(areaBounds.width, 4));
  });

