  test('raw chart overlays honor axis line types', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 150,
                'height': 100,
                'option': {
                  'xAxis': {
                    'axisLine': {
                      'lineStyle': {
                        'color': '#ff00ff',
                        'width': 4,
                        'type': 'dashed',
                      },
                    },
                  },
                  'yAxis': {
                    'axisLine': {
                      'lineStyle': {
                        'color': '#00ffff',
                        'width': 5,
                        'type': 'dotted',
                      },
                    },
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartXAxisLineType, 'dashed');
    expect(overlay.chartYAxisLineType, 'dotted');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(400, 300));
    final image = await recorder.endRecording().toImage(400, 300);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var cyanPixels = 0;
    var maxMagentaRowRuns = 0;
    var maxCyanColumnRuns = 0;
    for (var y = 0; y < image.height; y += 1) {
      var rowRuns = 0;
      var inMagentaRun = false;
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isMagenta = red > 180 && blue > 180 && green < 100;
        if (isMagenta) {
          magentaPixels += 1;
          if (!inMagentaRun) {
            rowRuns += 1;
          }
        }
        inMagentaRun = isMagenta;
        if (green > 180 && blue > 180 && red < 100) {
          cyanPixels += 1;
        }
      }
      maxMagentaRowRuns = math.max(maxMagentaRowRuns, rowRuns);
    }
    for (var x = 0; x < image.width; x += 1) {
      var columnRuns = 0;
      var inCyanRun = false;
      for (var y = 0; y < image.height; y += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isCyan = green > 180 && blue > 180 && red < 100;
        if (isCyan && !inCyanRun) {
          columnRuns += 1;
        }
        inCyanRun = isCyan;
      }
      maxCyanColumnRuns = math.max(maxCyanColumnRuns, columnRuns);
    }
    expect(magentaPixels, greaterThan(120));
    expect(cyanPixels, greaterThan(40));
    expect(maxMagentaRowRuns, greaterThan(4));
    expect(maxCyanColumnRuns, greaterThan(3));
  });

