    expect(overlay.chartYAxisLineSymbolRotationDegrees, 90);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(420, 300));
    final image = await recorder.endRecording().toImage(420, 300);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var rotatedMagentaPixels = 0;
    var rotatedGreenPixels = 0;
    var magentaMinY = image.height;
    var magentaMaxY = 0;
    var greenMinX = image.width;
    var greenMaxX = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (x >= 198 && x <= 235 && red > 180 && blue > 180 && green < 120) {
          rotatedMagentaPixels += 1;
          magentaMinY = math.min(magentaMinY, y);
          magentaMaxY = math.max(magentaMaxY, y);
        }
        if (y >= 120 && y <= 150 && green > 180 && red < 120 && blue < 120) {
          rotatedGreenPixels += 1;
          greenMinX = math.min(greenMinX, x);
          greenMaxX = math.max(greenMaxX, x);
        }
      }
    }
    expect(rotatedMagentaPixels, greaterThan(60));
    expect(magentaMaxY - magentaMinY, greaterThan(14));
    expect(rotatedGreenPixels, greaterThan(60));
    expect(greenMaxX - greenMinX, greaterThan(14));
  });

