            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 20,
                  'width': 150,
                  'height': 100,
                  'option': {
                    'xAxis': {
                      'axisTick': {
                        'show': true,
                        'inside': inside,
                        'length': 14,
                        'lineStyle': {'color': '#ff00ff', 'width': 3},
                      },
                    },
                    'yAxis': {
                      'axisTick': {
                        'show': true,
                        'inside': inside,
                        'length': 12,
                        'lineStyle': {'color': '#00ffff', 'width': 3},
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<ui.Image> paintWorkbook(FortuneWorkbook workbook) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(400, 300));
      return recorder.endRecording().toImage(400, 300);
    }

    ({int minX, int maxX, int minY, int maxY, int pixels}) colorBounds(
      ui.Image image,
      ByteData bytes,
      bool Function(int red, int green, int blue) matches,
    ) {
      var minX = image.width;
      var maxX = -1;
      var minY = image.height;
      var maxY = -1;
      var pixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            pixels += 1;
            minX = math.min(minX, x);
            maxX = math.max(maxX, x);
            minY = math.min(minY, y);
            maxY = math.max(maxY, y);
          }
        }
      }
      return (minX: minX, maxX: maxX, minY: minY, maxY: maxY, pixels: pixels);
    }

    final workbook = workbookFor(true);

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartXAxisTickInside, isTrue);
    expect(overlay.chartYAxisTickInside, isTrue);

    final insideImage = await paintWorkbook(workbook);
    final outsideImage = await paintWorkbook(workbookFor(false));
    final insideBytes = await insideImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    final outsideBytes = await outsideImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    expect(insideBytes, isNotNull);
    expect(outsideBytes, isNotNull);

    final insideMagenta = colorBounds(
      insideImage,
      insideBytes!,
      (red, green, blue) => red > 180 && blue > 180 && green < 100,
    );
    final outsideMagenta = colorBounds(
      outsideImage,
      outsideBytes!,
      (red, green, blue) => red > 180 && blue > 180 && green < 100,
    );
    final insideCyan = colorBounds(
      insideImage,
      insideBytes,
      (red, green, blue) => green > 180 && blue > 180 && red < 100,
    );
    final outsideCyan = colorBounds(
      outsideImage,
      outsideBytes,
      (red, green, blue) => green > 180 && blue > 180 && red < 100,
    );

    expect(insideMagenta.pixels, greaterThan(80));
    expect(outsideMagenta.pixels, greaterThan(80));
    expect(insideCyan.pixels, greaterThan(60));
    expect(outsideCyan.pixels, greaterThan(60));
    expect(insideMagenta.maxY, lessThan(outsideMagenta.maxY));
    expect(insideCyan.minX, greaterThan(outsideCyan.minX));
  });

