  test('raw chart overlays honor axis inverse direction', () async {
    FortuneWorkbook workbookFor({
      bool xInverse = false,
      bool yInverse = false,
    }) {
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 20,
                  'width': 170,
                  'height': 125,
                  'option': {
                    'xAxis': {
                      if (xInverse) 'inverse': true,
                      'data': ['A', 'B'],
                    },
                    'yAxis': {
                      if (yInverse) 'inverse': true,
                      'min': 0,
                      'max': 5,
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 5],
                        'lineStyle': {'color': '#ff00ff'},
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<({double covariance, int pixels})> paintSeriesRegions(
      FortuneWorkbook workbook,
    ) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(420, 300));
      final image = await recorder.endRecording().toImage(420, 300);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);
      expect(bytes, isNotNull);

      var pixels = 0;
      var sumX = 0.0;
      var sumY = 0.0;
      final points = <Offset>[];
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 120) {
            pixels += 1;
            sumX += x;
            sumY += y;
            points.add(Offset(x.toDouble(), y.toDouble()));
          }
        }
      }
      expect(pixels, greaterThan(20));
      final meanX = sumX / pixels;
      final meanY = sumY / pixels;
      final covariance = points.fold<double>(0, (total, point) {
        return total + (point.dx - meanX) * (point.dy - meanY);
      });
      return (covariance: covariance, pixels: pixels);
    }

    final xInverseWorkbook = workbookFor(xInverse: true);
    final yInverseWorkbook = workbookFor(yInverse: true);
    final xOverlay = fortuneRawShapeOverlays(
      xInverseWorkbook.activeSheet,
    ).single;
    final yOverlay = fortuneRawShapeOverlays(
      yInverseWorkbook.activeSheet,
    ).single;
    expect(xOverlay.chartXAxisInverse, isTrue);
    expect(xOverlay.chartYAxisInverse, isFalse);
    expect(yOverlay.chartXAxisInverse, isFalse);
    expect(yOverlay.chartYAxisInverse, isTrue);

    final normal = await paintSeriesRegions(workbookFor());
    final xReversed = await paintSeriesRegions(xInverseWorkbook);
    final yReversed = await paintSeriesRegions(yInverseWorkbook);

    expect(normal.covariance, lessThan(-100));
    expect(xReversed.covariance, greaterThan(100));
    expect(yReversed.covariance, greaterThan(100));
  });

