  test('raw chart overlays honor axis label border types', () async {
    Map<String, Object?> chart(String id, int left, String? borderType) {
      final axisLabel = <String, Object?>{
        'color': '#000000',
        'fontSize': 12,
        'backgroundColor': '#ffffff',
        'borderColor': '#ff0000',
        'borderWidth': 4,
        'borderRadius': 0,
        'width': 72,
        'height': 28,
        'padding': 0,
      };
      if (borderType != null) {
        axisLabel['borderType'] = borderType;
      }
      return {
        'id': id,
        'left': left,
        'top': 20,
        'width': 150,
        'height': 110,
        'option': {
          'xAxis': {
            'data': ['Label'],
            'axisLabel': axisLabel,
          },
          'yAxis': {
            'axisLabel': {'show': false},
          },
          'series': [
            {
              'type': 'line',
              'data': [1],
            },
          ],
        },
      };
    }

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: {
            'chart': [
              chart('solidAxisLabelBorder', 20, null),
              chart('dashedAxisLabelBorder', 210, 'dashed'),
              chart('dottedAxisLabelBorder', 400, 'dotted'),
            ],
          },
        ),
      ],
    );

    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    expect(overlays[0].chartXAxisLabelBorderType, isNull);
    expect(overlays[1].chartXAxisLabelBorderType, 'dashed');
    expect(overlays[2].chartXAxisLabelBorderType, 'dotted');

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    for (final overlay in overlays) {
      fortuneDrawRawShapeOverlay(
        canvas,
        overlay.rect,
        overlay,
        const Rect.fromLTWH(0, 0, 620, 190),
      );
    }
    final image = await recorder.endRecording().toImage(620, 190);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    int redPixelsIn(int left, int right) {
      var pixels = 0;
      for (var y = 80; y < 175; y += 1) {
        for (var x = left; x < right; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green < 100 && blue < 100) {
            pixels += 1;
          }
        }
      }
      return pixels;
    }

    final solidRedPixels = redPixelsIn(20, 170);
    final dashedRedPixels = redPixelsIn(210, 360);
    final dottedRedPixels = redPixelsIn(400, 550);

    expect(solidRedPixels, greaterThan(200));
    expect(dashedRedPixels, greaterThan(60));
    expect(dottedRedPixels, greaterThan(60));
    expect(dashedRedPixels, lessThan(solidRedPixels * 0.7));
    expect(dottedRedPixels, lessThan(solidRedPixels * 0.7));
