  test(
    'raw chart overlays honor axis label align and vertical align',
    () async {
      FortuneWorkbook workbookFor({String? align, String? verticalAlign}) {
        return FortuneWorkbook(
          sheets: [
            FortuneSheet(
              id: 's1',
              name: 'Sheet1',
              extraFields: {
                'chart': [
                  {
                    'id': 'chart1',
                    'left': 20,
                    'top': 20,
                    'width': 180,
                    'height': 120,
                    'option': {
                      'xAxis': {
                        'data': ['X'],
                        'axisLabel': {
                          'color': '#111111',
                          'fontSize': 16,
                          'backgroundColor': '#ff00ff',
                          'width': 80,
                          'height': 32,
                          'align': ?align,
                          'verticalAlign': ?verticalAlign,
                        },
                      },
                      'yAxis': {
                        'data': ['Y'],
                        'axisLabel': {
                          'color': '#111111',
                          'fontSize': 16,
                          'backgroundColor': '#00ffff',
                          'width': 80,
                          'height': 32,
                          'align': ?align,
                          'verticalAlign': ?verticalAlign,
                        },
                      },
                      'series': [
                        {
                          'type': 'line',
                          'data': [1, 4, 2, 5],
                        },
                      ],
                    },
                  },
                ],
              },
            ),
          ],
        );
      }

      Future<({int left, int right, int top, int bottom})> textDistribution(
        FortuneWorkbook workbook,
        bool Function(int red, int green, int blue) background,
      ) async {
        final recorder = ui.PictureRecorder();
        final canvas = Canvas(recorder);
        FortuneSheetPainter(
          workbook: workbook,
          selection: const FortuneSelection(row: 10, column: 10),
          scrollOffset: Offset.zero,
          sheetTabScrollOffset: 0,
          textDirection: TextDirection.ltr,
        ).paint(canvas, const Size(440, 330));
        final image = await recorder.endRecording().toImage(440, 330);
        final bytes = await image.toByteData(
          format: ui.ImageByteFormat.rawRgba,
        );
        expect(bytes, isNotNull);

        var minX = image.width;
        var maxX = -1;
        var minY = image.height;
        var maxY = -1;
        for (var y = 0; y < image.height; y += 1) {
          for (var x = 0; x < image.width; x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (background(red, green, blue)) {
              minX = math.min(minX, x);
              maxX = math.max(maxX, x);
              minY = math.min(minY, y);
              maxY = math.max(maxY, y);
            }
          }
        }
        expect(maxX, greaterThanOrEqualTo(minX));
        expect(maxY, greaterThanOrEqualTo(minY));

        final centerX = (minX + maxX) / 2;
        final centerY = (minY + maxY) / 2;
        var left = 0;
        var right = 0;
        var top = 0;
        var bottom = 0;
        for (var y = minY; y <= maxY; y += 1) {
          for (var x = minX; x <= maxX; x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (red < 90 && green < 90 && blue < 90) {
              if (x < centerX) {
                left += 1;
              } else {
                right += 1;
              }
              if (y < centerY) {
                top += 1;
              } else {
                bottom += 1;
              }
            }
          }
        }
        return (left: left, right: right, top: top, bottom: bottom);
      }

      final alignedWorkbook = workbookFor(
        align: 'right',
        verticalAlign: 'bottom',
      );
      final overlay = fortuneRawShapeOverlays(
        alignedWorkbook.activeSheet,
      ).single;
      expect(overlay.chartXAxisLabelAlign, 'right');
      expect(overlay.chartYAxisLabelAlign, 'right');
      expect(overlay.chartXAxisLabelVerticalAlign, 'bottom');
      expect(overlay.chartYAxisLabelVerticalAlign, 'bottom');

      final defaultMagenta = await textDistribution(
        workbookFor(),
        (red, green, blue) => red > 180 && blue > 180 && green < 120,
      );
      final alignedMagenta = await textDistribution(
        alignedWorkbook,
        (red, green, blue) => red > 180 && blue > 180 && green < 120,
      );
      expect(defaultMagenta.left, greaterThan(defaultMagenta.right));
      expect(defaultMagenta.top, greaterThan(defaultMagenta.bottom));
      expect(alignedMagenta.right, greaterThan(alignedMagenta.left));
      expect(alignedMagenta.bottom, greaterThan(alignedMagenta.top));
    },
  );

