  test('raw chart overlays honor axis label margins', () async {
    FortuneWorkbook workbookFor(double margin) {
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 20,
                  'width': 160,
                  'height': 110,
                  'option': {
                    'xAxis': {
                      'data': ['Start', 'End'],
                      'axisLine': {
                        'lineStyle': {'color': '#00ff00'},
                      },
                      'axisLabel': {
                        'color': '#ff00ff',
                        'fontSize': 12,
                        'margin': margin,
                      },
                    },
                    'yAxis': {
                      'data': ['High', 'Low'],
                      'axisLine': {
                        'lineStyle': {'color': '#00ff00'},
                      },
                      'axisLabel': {
                        'color': '#00ffff',
                        'fontSize': 12,
                        'margin': margin,
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<ui.Image> paintWorkbook(FortuneWorkbook workbook) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(420, 320));
      return recorder.endRecording().toImage(420, 320);
    }

    ({int minX, int maxY, int minY, int pixels}) colorBounds(
      ui.Image image,
      ByteData bytes,
      bool Function(int red, int green, int blue) matches,
    ) {
      var minX = image.width;
      var minY = image.height;
      var maxY = -1;
      var pixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (matches(red, green, blue)) {
            pixels += 1;
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxY = math.max(maxY, y);
          }
        }
      }
      return (minX: minX, maxY: maxY, minY: minY, pixels: pixels);
    }

    final largeMarginWorkbook = workbookFor(18);
    final overlay = fortuneRawShapeOverlays(
      largeMarginWorkbook.activeSheet,
    ).single;
    expect(overlay.chartXAxisLabelMargin, 18);
    expect(overlay.chartYAxisLabelMargin, 18);

    final smallImage = await paintWorkbook(workbookFor(3));
    final largeImage = await paintWorkbook(largeMarginWorkbook);
    final smallBytes = await smallImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    final largeBytes = await largeImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    expect(smallBytes, isNotNull);
    expect(largeBytes, isNotNull);

    final smallMagenta = colorBounds(
      smallImage,
      smallBytes!,
      (red, green, blue) => red > 180 && blue > 180 && green < 100,
    );
    final largeMagenta = colorBounds(
      largeImage,
      largeBytes!,
      (red, green, blue) => red > 180 && blue > 180 && green < 100,
    );
    final smallCyan = colorBounds(
      smallImage,
      smallBytes,
      (red, green, blue) => green > 180 && blue > 180 && red < 100,
    );
    final largeCyan = colorBounds(
      largeImage,
      largeBytes,
      (red, green, blue) => green > 180 && blue > 180 && red < 100,
    );
    final smallGreen = colorBounds(
      smallImage,
      smallBytes,
      (red, green, blue) => green > 180 && red < 100 && blue < 100,
    );
    final largeGreen = colorBounds(
      largeImage,
      largeBytes,
      (red, green, blue) => green > 180 && red < 100 && blue < 100,
    );

    expect(largeMagenta.pixels, greaterThan(40));
    expect(largeCyan.pixels, greaterThan(40));
    expect(
      largeMagenta.minY - largeGreen.maxY,
      greaterThan(smallMagenta.minY - smallGreen.maxY),
    );
    expect(largeCyan.minX, lessThan(smallCyan.minX));
  });

