          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 170,
                'height': 120,
                'option': {
                  'xAxis': {
                    'data': ['RotatedJanuary', 'Feb', 'Mar', 'RotatedApril'],
                    'axisLabel': {
                      'color': '#ff00ff',
                      'fontSize': 12,
                      'rotate': 60,
                    },
                  },
                  'yAxis': {
                    'data': ['Top', 'Bottom'],
                    'axisLabel': {'color': '#00ffff', 'rotation': -30},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartXAxisLabelRotationDegrees, 60);
    expect(overlay.chartYAxisLabelRotationDegrees, -30);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(440, 320));
    final image = await recorder.endRecording().toImage(440, 320);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var minMagentaY = image.height;
    var maxMagentaY = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 120) {
          magentaPixels += 1;
          if (y < minMagentaY) {
            minMagentaY = y;
          }
          if (y > maxMagentaY) {
            maxMagentaY = y;
          }
        }
      }
    }
    expect(magentaPixels, greaterThan(20));
    expect(maxMagentaY - minMagentaY, greaterThanOrEqualTo(24));
  });

