  test('raw chart overlays honor axis name rotation', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 20,
                'width': 170,
                'height': 120,
                'option': {
                  'xAxis': {
                    'name': 'RotatedMonthAxis',
                    'nameRotate': 60,
                    'data': ['Jan', 'Feb', 'Mar', 'Apr'],
                    'axisLabel': {'show': false},
                    'nameTextStyle': {'color': '#ff00ff', 'fontSize': 12},
                  },
                  'yAxis': {
                    'name': 'RotatedRevenue',
                    'nameRotation': -30,
                    'min': 0,
                    'max': 100,
                    'axisLabel': {'show': false},
                    'nameTextStyle': {'color': '#00ffff'},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
    expect(overlay.chartXAxisNameRotationDegrees, 60);
    expect(overlay.chartYAxisNameRotationDegrees, -30);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(440, 320));
    final image = await recorder.endRecording().toImage(440, 320);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var magentaPixels = 0;
    var minMagentaY = image.height;
    var maxMagentaY = 0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 120) {
          magentaPixels += 1;
          if (y < minMagentaY) {
            minMagentaY = y;
          }
          if (y > maxMagentaY) {
            maxMagentaY = y;
          }
        }
      }
    }
    expect(magentaPixels, greaterThan(20));
    expect(maxMagentaY - minMagentaY, greaterThanOrEqualTo(20));
  });

  test('raw chart overlays rotate y axis name bounds', () async {
    FortuneWorkbook workbookFor(double? rotation) {
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 20,
                  'width': 220,
                  'height': 150,
                  'option': {
                    'xAxis': {
                      'data': ['Jan', 'Feb', 'Mar', 'Apr'],
                      'axisLabel': {'show': false},
                    },
                    'yAxis': {
                      'name': 'RotatedY',
                      'nameRotate': ?rotation,
                      'min': 0,
                      'max': 100,
                      'axisLabel': {'show': false},
                      'nameTextStyle': {
                        'color': '#111111',
                        'fontSize': 16,
                        'backgroundColor': '#00ffff',
                        'width': 92,
                        'height': 28,
                        'borderRadius': 0,
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<({int pixels, int minX, int maxX, int minY, int maxY})> cyanBounds(
      FortuneWorkbook workbook,
    ) async {
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 10, column: 10),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
      ).paint(canvas, const Size(460, 350));
      final image = await recorder.endRecording().toImage(460, 350);
      final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);
      expect(bytes, isNotNull);

      var pixels = 0;
      var minX = image.width;
      var maxX = -1;
      var minY = image.height;
      var maxY = -1;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (green > 180 && blue > 180 && red < 120) {
            pixels += 1;
            minX = math.min(minX, x);
            maxX = math.max(maxX, x);
            minY = math.min(minY, y);
            maxY = math.max(maxY, y);
          }
        }
      }
      return (pixels: pixels, minX: minX, maxX: maxX, minY: minY, maxY: maxY);
    }

    final rotatedWorkbook = workbookFor(-60);
    final overlay = fortuneRawShapeOverlays(rotatedWorkbook.activeSheet).single;
    expect(overlay.chartYAxisNameRotationDegrees, -60);

    final plainBounds = await cyanBounds(workbookFor(null));
    final rotatedBounds = await cyanBounds(rotatedWorkbook);
    final plainHeight = plainBounds.maxY - plainBounds.minY;
    final rotatedHeight = rotatedBounds.maxY - rotatedBounds.minY;
    final plainWidth = plainBounds.maxX - plainBounds.minX;
    final rotatedWidth = rotatedBounds.maxX - rotatedBounds.minX;

    expect(plainBounds.pixels, greaterThan(500));
    expect(rotatedBounds.pixels, greaterThan(500));
    expect(rotatedHeight, greaterThan(plainHeight + 25));
    expect(rotatedWidth, lessThan(plainWidth + 10));
  });

