                ),
              ],
            ),
          ],
        ),
      ],
    );

    final computedBorders = FortuneBorderCompute.compute(workbook.activeSheet);
    expect(
      computedBorders[const FortuneCellCoord(0, 0)]?.top?.color,
      const Color(0xffff0000),
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
