  test('cell text honors horizontal and vertical alignment', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          defaultColWidth: 90,
          defaultRowHeight: 60,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'I',
              foreground: Color(0xffff0000),
              fontSize: 24,
              verticalAlign: '1',
            ),
            const FortuneCellCoord(0, 2): const FortuneCell(
              value: 'I',
              foreground: Color(0xffff0000),
              fontSize: 24,
              horizontalAlign: '2',
              verticalAlign: '2',
            ),
            const FortuneCellCoord(0, 4): const FortuneCell(
              value: 'I',
              foreground: Color(0xffff0000),
              fontSize: 24,
              horizontalAlign: '0',
            ),
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(560, 220));
    final image = await recorder.endRecording().toImage(560, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    ({int minX, int maxX, int minY, int maxY, int count}) redBounds(
      Rect region,
    ) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      var count = 0;
      for (var y = region.top.floor(); y < region.bottom.ceil(); y += 1) {
        for (var x = region.left.floor(); x < region.right.ceil(); x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green < 80 && blue < 80) {
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
            count += 1;
          }
        }
      }
      return (minX: minX, maxX: maxX, minY: minY, maxY: maxY, count: count);
    }

    final topLeft = redBounds(const Rect.fromLTWH(46, 90, 90, 60));
    final bottomRight = redBounds(const Rect.fromLTWH(226, 90, 90, 60));
    final centered = redBounds(const Rect.fromLTWH(406, 90, 90, 60));

    expect(topLeft.count, greaterThan(8));
    expect(bottomRight.count, greaterThan(8));
    expect(centered.count, greaterThan(8));
    expect(topLeft.minX, lessThan(60));
    expect(topLeft.minY, lessThan(102));
    expect(bottomRight.maxX, greaterThan(300));
    expect(bottomRight.maxY, greaterThan(140));
    expect(centered.minX, greaterThan(430));
    expect(centered.maxX, lessThan(470));
    expect(centered.minY, greaterThan(105));
    expect(centered.maxY, lessThan(140));
  });

