  test('cell font size changes rendered glyph bounds', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          defaultColWidth: 90,
          defaultRowHeight: 60,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'SIZE',
              foreground: Color(0xffff0000),
              fontSize: 12,
            ),
            const FortuneCellCoord(0, 2): const FortuneCell(
              value: 'SIZE',
              foreground: Color(0xffff0000),
              fontSize: 28,
            ),
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(380, 220));
    final image = await recorder.endRecording().toImage(380, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    ({int width, int height, int count}) redBounds(Rect region) {
      var minX = image.width;
      var minY = image.height;
      var maxX = -1;
      var maxY = -1;
      var count = 0;
      for (var y = region.top.floor(); y < region.bottom.ceil(); y += 1) {
        for (var x = region.left.floor(); x < region.right.ceil(); x += 1) {
          final offset = ((y * image.width) + x) * 4;
          final red = bytes!.getUint8(offset);
          final green = bytes.getUint8(offset + 1);
          final blue = bytes.getUint8(offset + 2);
          if (red > 180 && green < 80 && blue < 80) {
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxX = math.max(maxX, x);
            maxY = math.max(maxY, y);
            count += 1;
          }
        }
      }
      return (
        width: maxX < minX ? 0 : maxX - minX + 1,
        height: maxY < minY ? 0 : maxY - minY + 1,
        count: count,
      );
    }

    final small = redBounds(const Rect.fromLTWH(46, 90, 90, 60));
    final large = redBounds(const Rect.fromLTWH(226, 90, 90, 60));

    expect(small.count, greaterThan(8));
    expect(large.count, greaterThan(small.count * 2));
    expect(large.width, greaterThan(small.width + 24));
    expect(large.height, greaterThan(small.height + 8));
  });

