        required int yStart,
        required int yEnd,
        required bool Function(int red, int green, int blue) matches,
      }) {
        var count = 0;
        for (var y = yStart; y < yEnd; y += 1) {
          for (var x = 48; x < 136; x += 1) {
            final offset = ((y * image.width) + x) * 4;
            final red = bytes!.getUint8(offset);
            final green = bytes.getUint8(offset + 1);
            final blue = bytes.getUint8(offset + 2);
            if (matches(red, green, blue)) {
              count += 1;
            }
          }
        }
        return count;
      }

      final alternateRedPixels = countTextPixels(
        yStart: 92,
        yEnd: 118,
        matches: (red, green, blue) => red > 180 && green < 80 && blue < 80,
      );
      final cellBluePixels = countTextPixels(
        yStart: 124,
        yEnd: 150,
        matches: (red, green, blue) => red < 80 && green < 80 && blue > 180,
      );
      final conditionGreenPixels = countTextPixels(
        yStart: 156,
        yEnd: 182,
        matches: (red, green, blue) => red < 80 && green > 120 && blue < 80,
      );

      expect(alternateRedPixels, greaterThan(0));
      expect(cellBluePixels, greaterThan(0));
      expect(conditionGreenPixels, greaterThan(0));
    },
  );

