    final image = await recorder.endRecording().toImage(260, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var leftBluePixels = 0;
    var rightBluePixels = 0;
    var middleColoredPixels = 0;
    for (var y = 48; y < 112; y += 1) {
      for (var x = 32; x < 132; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isBlue = blue > 180 && red < 120 && green < 120;
        final isGreen = green > 180 && red < 120 && blue < 120;
        if (x < 68 && isBlue) {
          leftBluePixels += 1;
        }
        if (x > 92 && isBlue) {
          rightBluePixels += 1;
        }
        if (x >= 76 && x <= 82 && (isBlue || isGreen)) {
          middleColoredPixels += 1;
        }
      }
    }
    expect(leftBluePixels, greaterThan(20));
    expect(rightBluePixels, greaterThan(20));
    expect(middleColoredPixels, lessThan(10));
  });

  test('cell stack bar sparklines honor raw groups and spacing', () async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              sparkline: {
                'type': 'stackbar',
                'data': [1, 1, 1, 1],
                'stackGroups': [
                  [1, 1],
                  [1, 1],
                ],
                'barSpacing': 16,
                'chartRangeMax': 2,
                'stackedBarColors': ['#0000ff', '#00ff00'],
              },
            ),
          },
        ),
      ],
    );

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 10, column: 10),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    ).paint(canvas, const Size(260, 220));
    final image = await recorder.endRecording().toImage(260, 220);
    final bytes = await image.toByteData(format: ui.ImageByteFormat.rawRgba);

    expect(bytes, isNotNull);
    var bluePixels = 0;
    final coloredRows = <int>{};
    for (var y = 48; y < 112; y += 1) {
      var rowColoredPixels = 0;
      for (var x = 32; x < 132; x += 1) {
        final offset = ((y * image.width) + x) * 4;
        final red = bytes!.getUint8(offset);
        final green = bytes.getUint8(offset + 1);
        final blue = bytes.getUint8(offset + 2);
        final isBlue = blue > 180 && red < 120 && green < 120;
        final isGreen = green > 180 && red < 120 && blue < 120;
        if (isBlue) {
          bluePixels += 1;
        }
        if (isBlue || isGreen) {
          rowColoredPixels += 1;
        }
      }
      if (rowColoredPixels > 10) {
        coloredRows.add(y);
      }
    }
    var bands = 0;
    var previousRow = -2;
    for (final row in coloredRows.toList()..sort()) {
      if (row != previousRow + 1) {
        bands += 1;
      }
      previousRow = row;
    }
    expect(bluePixels, greaterThan(20));
    expect(bands, 2);
  });

